} from 'recharts';
import { Patient, Appointment, Medicine, Invoice, Expense, Salary } from '../types';

interface Props {
  patients: Patient[];
  appointments: Appointment[];
  inventory: Medicine[];
  invoices: Invoice[];
  expenses: Expense[];
  salaries: Salary[];
}

const ReportsView: React.FC<Props> = ({ patients, appointments, inventory, invoices, expenses, salaries }) => {
  const [reportType, setReportType] = useState<'financial' | 'inventory' | 'staff'>('financial');

  const totalRevenue = invoices.filter(inv => inv.status === 'Paid').reduce((acc, i) => acc + i.amount, 0);
  const totalExpenses = expenses.reduce((acc, i) => acc + i.amount, 0);
  const totalSalaries = salaries.reduce((acc, i) => acc + i.amount, 0);
  const netProfit = totalRevenue - totalExpenses - totalSalaries;

  const financialData = [
    { name: 'Revenue', value: totalRevenue, fill: '#10b981' },
    { name: 'Op. Expenses', value: totalExpenses, fill: '#f43f5e' },
    { name: 'Payroll', value: totalSalaries, fill: '#f59e0b' },
  ];

  const inventoryData = inventory.map(item => ({
    name: item.name,
    stock: item.stock
  }));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Intelligence & Reports</h1>
          <p className="text-slate-500">Business insights and operational summaries.</p>
        </div>
        <div className="relative">
          <select 
            value={reportType}
            onChange={(e) => setReportType(e.target.value as any)}
            className="appearance-none bg-white border border-slate-200 px-6 py-2.5 pr-10 rounded-xl text-sm font-bold shadow-sm outline-none focus:ring-2 focus:ring-blue-500/20"
          >
            <option value="financial">Financial Performance</option>
            <option value="inventory">Inventory Analysis</option>
            <option value="staff">Staff Productivity</option>
          </select>
          <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
        </div>
      </div>

      {reportType === 'financial' && (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <ReportStat label="Gross Revenue" value={`$${totalRevenue.toLocaleString()}`} color="emerald" />
            <ReportStat label="Op. Expenses" value={`$${totalExpenses.toLocaleString()}`} color="rose" />
            <ReportStat label="Payroll" value={`$${totalSalaries.toLocaleString()}`} color="amber" />
            <ReportStat label="Net Profit" value={`$${netProfit.toLocaleString()}`} color="blue" />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-80">
              <h3 className="font-bold mb-4">Revenue vs Costs Distribution</h3>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={financialData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} />
                  <Tooltip cursor={{fill: '#f8fafc'}} />
                  <Bar dataKey="value" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <h3 className="font-bold mb-4">Clinic Health Summary</h3>
              <div className="space-y-4">
                <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="text-sm text-slate-600 font-medium">Profit Margin</span>
                  <span className={`font-bold ${netProfit > 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                    {((netProfit / totalRevenue) * 100).toFixed(1)}%
                  </span>
                </div>
                <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="text-sm text-slate-600 font-medium">Avg. Invoiced Amount</span>
                  <span className="font-bold text-blue-600">
                    ${(totalRevenue / invoices.length || 0).toFixed(2)}
                  </span>
                </div>
                <div className="flex justify-between items-center p-3 bg-slate-50 rounded-xl">
                  <span className="text-sm text-slate-600 font-medium">Overhead Ratio</span>
                  <span className="font-bold text-amber-600">
                    {(((totalExpenses + totalSalaries) / totalRevenue) * 100).toFixed(1)}%
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {reportType === 'inventory' && (
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-[450px] animate-in fade-in duration-500">
          <h3 className="font-bold mb-6">Current Stock Levels by Item</h3>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={inventoryData} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
              <XAxis type="number" axisLine={false} tickLine={false} />
              <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} width={100} />
