                    <p className="font-bold text-slate-900">{s.staffName}</p>
                    <p className="text-xs text-slate-500">{s.role}</p>
                  </div>
                  <p className="font-mono text-sm font-bold text-blue-600">${s.amount}</p>
                </div>
              ))}
            </div>
          </div>
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col items-center justify-center text-center">
            <Users className="w-12 h-12 text-slate-200 mb-4" />
            <h3 className="text-lg font-bold">Staff Performance Metrics</h3>
            <p className="text-sm text-slate-500 mt-2 max-w-xs">Detailed patient conversion and consultation efficiency charts will be available once appointment completion data reaches threshold.</p>
          </div>
        </div>
      )}
    </div>
  );
};

const ReportStat = ({ label, value, color }: { label: string, value: string, color: string }) => {
  const colorMap: any = {
    emerald: 'bg-emerald-50 text-emerald-600',
    rose: 'bg-rose-50 text-rose-600',
    amber: 'bg-amber-50 text-amber-600',
    blue: 'bg-blue-50 text-blue-600'
  };
  return (
    <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1">{label}</p>
      <p className={`text-xl font-bold ${colorMap[color].split(' ')[1]}`}>{value}</p>
    </div>
  );
};

