          {t('addUser')}
        </button>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b border-gray-100 text-xs uppercase text-gray-500 font-bold">
            <tr>
              <th className="p-4">{t('name')}</th>
              <th className="p-4">{t('email')}</th>
              <th className="p-4">{t('role')}</th>
              <th className="p-4 text-right">{t('actions')}</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50">
            {appUsers.map(u => (
              <tr key={u.id} className="hover:bg-gray-50 transition-colors">
                <td className="p-4 flex items-center gap-3">
                  <img src={u.avatar} className="w-8 h-8 rounded-full bg-gray-100" alt="" />
                  <span className="font-bold text-gray-800">{u.name}</span>
                  {u.id === currentUser?.id && <span className="bg-blue-100 text-blue-600 text-[10px] px-2 py-0.5 rounded-full">You</span>}
                </td>
                <td className="p-4 text-sm text-gray-600">{u.email}</td>
                <td className="p-4">
                  <span className={`text-xs px-2 py-1 rounded-full font-bold 
                    ${u.role === 'Admin' ? 'bg-purple-100 text-purple-700' : 
