import React, { useState } from 'react';
// Fix: Added Package to imports from lucide-react
import { ShoppingCart, ShoppingBag, Trash2, ChevronDown, CheckCircle2, Package } from 'lucide-react';
import { Medicine, CartItem, Product } from '../types';
import { InvoiceReceipt } from '../components/InvoiceReceipt';

interface Props {
  products: Product[];
  processSale: (items: { id: string; quantity: number }[], total: number, method: string) => void;
  t: (key: string) => string;
}

const POSView: React.FC<Props> = ({ products, processSale, t }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showCheckout, setShowCheckout] = useState(false);

  // Invoice State
  const [showInvoice, setShowInvoice] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<{
    items: CartItem[];
    total: number;
    id: string;
    method: string;
    date: string;
  } | null>(null);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return;

    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) return;
      setCart(cart.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const handleCheckout = (method: 'Cash' | 'Zaad') => {
    if (cart.length === 0) return;

    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const transactionId = Math.floor(Math.random() * 900000 + 100000).toString();
    const date = new Date().toLocaleString();

    // Save transaction
    processSale(cart.map(i => ({ id: i.id, quantity: i.quantity })), total, method);

    // Set Invoice Data
    setLastTransaction({
      items: [...cart],
      total,
      id: transactionId,
      method,
      date
    });
    setShowInvoice(true);

    // Reset Cart
    setCart([]);
    setShowCheckout(false);
  };

  const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <div className="h-[calc(100vh-120px)] flex flex-col md:flex-row overflow-hidden bg-gray-50 relative rounded-2xl border border-gray-200">

      {/* Invoice Modal */}
      {showInvoice && lastTransaction && (
        <InvoiceReceipt 
          items={lastTransaction.items}
          total={lastTransaction.total}
          transactionId={lastTransaction.id}
          date={lastTransaction.date}
          method={lastTransaction.method}
          onClose={() => setShowInvoice(false)}
        />
      )}

      {/* Product Grid */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 no-scrollbar">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
            <span className="p-2 bg-blue-100 text-blue-600 rounded-lg">
              <ShoppingBag className="w-6 h-6" />
            </span>
            {t('pos')}
          </h2>
          <div className="text-sm font-medium text-slate-500 bg-white px-3 py-1 rounded-full border">
            {products.length} Products Available
          </div>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
          {products.map(product => (
            <div 
              key={product.id} 
              onClick={() => addToCart(product)}
              className={`bg-white p-4 rounded-2xl shadow-sm border border-gray-100 cursor-pointer transition-all active:scale-95 flex flex-col ${product.stock === 0 ? 'opacity-50 grayscale pointer-events-none' : 'hover:shadow-md hover:border-blue-200 group'}`}
            >
              <div className="h-24 bg-gray-50 rounded-xl mb-3 flex items-center justify-center text-gray-300 relative overflow-hidden transition-colors group-hover:bg-blue-50/50">
                 <Package className="w-10 h-10 transition-transform group-hover:scale-110" />
                {product.stock === 0 && (
                  <div className="absolute inset-0 bg-black/5 flex items-center justify-center">
                    <span className="bg-rose-500 text-white text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider">Out of Stock</span>
                  </div>
                )}
              </div>
              <h3 className="font-bold text-gray-800 text-sm mb-1 truncate">{product.name}</h3>
              <div className="flex justify-between items-center mt-auto">
                 <span className="text-blue-600 font-bold">${product.price.toFixed(2)}</span>
                 <span className={`text-[10px] px-2 py-1 rounded-full font-bold ${product.stock < 5 ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                    {product.stock} {t('stock')}
                 </span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Cart Sidebar (Desktop) */}
      <div className={`md:w-96 bg-white border-l border-gray-200 flex flex-col shadow-2xl md:shadow-none absolute md:relative inset-0 md:inset-auto z-40 transition-transform duration-300 transform ${showCheckout ? 'translate-y-0' : 'translate-y-full md:translate-y-0'}`}>

        {/* Mobile Header for Cart */}
        <div className="md:hidden flex justify-between items-center p-4 border-b border-gray-100">
          <h3 className="font-bold text-lg">Checkout Details</h3>
          <button onClick={() => setShowCheckout(false)} className="p-2 bg-gray-100 rounded-full">
            <ChevronDown className="w-5 h-5" />
          </button>
        </div>

        <div className="p-4 border-b flex items-center gap-2">
          <ShoppingCart className="w-5 h-5 text-gray-400" />
          <h3 className="font-bold text-gray-800 uppercase tracking-widest text-xs">Current Selection</h3>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-50 text-center">
               <ShoppingBag className="w-16 h-16 mb-4 stroke-1" />
               <p className="text-sm font-medium">Your basket is empty.<br/>Tap items to add them.</p>
             </div>
          ) : (
            cart.map((item, index) => (
              <div key={index} className="flex items-center justify-between p-3 bg-gray-50 rounded-xl border border-transparent hover:border-gray-200 transition-all">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center font-bold text-gray-500 border border-gray-100">x{item.quantity}</div>
                   <div>
                     <p className="font-bold text-gray-800 text-sm truncate w-32">{item.name}</p>
                     <p className="text-xs text-blue-600 font-bold">${(item.price * item.quantity).toFixed(2)}</p>
                   </div>
                </div>
                <button onClick={() => removeFromCart(item.id)} className="text-gray-400 hover:text-rose-600 p-2 transition-colors">
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            ))
          )}
        </div>

        <div className="p-6 bg-slate-50 border-t border-gray-200 rounded-b-2xl">
          <div className="flex justify-between items-center mb-6">
            <span className="text-gray-500 font-bold uppercase tracking-widest text-[10px]">{t('total')} Payable</span>
            <span className="text-3xl font-black text-gray-900">${total.toFixed(2)}</span>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button 
              onClick={() => handleCheckout('Cash')}
              disabled={cart.length === 0}
              className="py-4 px-4 bg-white border border-gray-200 text-gray-700 font-black rounded-xl text-xs hover:bg-gray-100 transition-all uppercase disabled:opacity-50"
            >
              Cash Payment
            </button>
            <button 
              onClick={() => handleCheckout('Zaad')}
              disabled={cart.length === 0}
              className="py-4 px-4 bg-emerald-600 text-white font-black rounded-xl text-xs hover:bg-emerald-700 shadow-lg shadow-emerald-600/20 transition-all uppercase disabled:opacity-50"
            >
              Zaad / Dahab
            </button>
          </div>
        </div>
      </div>

      {/* Floating Action Button for Mobile Cart Trigger */}
      <div className="md:hidden fixed bottom-6 right-6 z-30">
        <button 
           onClick={() => setShowCheckout(true)}
           className="bg-gray-900 text-white p-5 rounded-full shadow-2xl flex items-center gap-3 relative scale-110"
        >
          <ShoppingCart className="w-6 h-6" />
          <span className="font-black">${total.toFixed(0)}</span>
          {cart.length > 0 && <span className="absolute -top-1 -right-1 w-6 h-6 bg-rose-500 rounded-full text-[10px] font-black flex items-center justify-center border-2 border-white">{cart.length}</span>}
        </button>
      </div>

    </div>
  );
};

export default POSView;

