    { id: 'users', label: 'Personnel', icon: UserCircle },
    { id: 'reports', label: 'Reports', icon: BarChart3 },
    { id: 'ai-assistant', label: 'AI Helper', icon: Bot },
  ];

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900">
      <aside className={`bg-[#0d1526] text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col shrink-0 overflow-hidden border-r border-white/5`}>
        <div className="p-6 flex flex-col items-center gap-2 border-b border-white/5">
          <div className="flex items-center gap-3">
            <div className="bg-white p-0.5 rounded-xl">
              <DhoolLogo />
            </div>
            {isSidebarOpen && (
              <div className="flex flex-col">
                <span className="text-xl font-extrabold tracking-tighter text-blue-500 uppercase">DHOOL</span>
                <span className="text-[10px] font-bold tracking-widest text-emerald-400 -mt-1 uppercase">Dental Clinic</span>
              </div>
            )}
          </div>
          {isSidebarOpen && <span className="text-[8px] text-slate-400 font-bold italic mt-2 uppercase tracking-[0.2em] opacity-80">YOUR SMILE IS OUR MISSION</span>}
        </div>
        <nav className="flex-1 mt-6 px-3">
          {navItems.map((item) => (
            <button
