import React, { useState } from 'react';
import { Package, Search, Plus, AlertTriangle, Filter, RefreshCw, ShoppingBag, Trash2, X, Camera, Image as ImageIcon } from 'lucide-react';
import { Medicine } from '../types';

interface Props {
  inventory: Medicine[];
  setInventory: React.Dispatch<React.SetStateAction<Medicine[]>>;
}

const PharmacyView: React.FC<Props> = ({ inventory, setInventory }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newMed, setNewMed] = useState({ 
    name: '', 
    stock: '', 
    price: '', 
    expiry: '', 
    category: 'General',
    image: '' 
  });

  const handleDelete = (id: string) => {
    if (confirm('Remove this product from inventory?')) setInventory(prev => prev.filter(m => m.id !== id));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewMed(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    const m: Medicine = {
      id: Math.random().toString(36).substr(2, 5).toUpperCase(),
      name: newMed.name,
      stock: parseInt(newMed.stock),
      price: parseFloat(newMed.price),
      expiryDate: newMed.expiry,
      category: newMed.category,
      image: newMed.image
    };
    setInventory(prev => [...prev, m]);
    setIsModalOpen(false);
    setNewMed({ name: '', stock: '', price: '', expiry: '', category: 'General', image: '' });
  };

  const filteredMeds = inventory.filter(m => 
    m.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Pharmacy Inventory</h1>
          <p className="text-slate-500 font-medium">Track medication levels, batches, and visual identification.</p>
        </div>
        <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 px-6 py-3 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-600/20">
          <Plus className="w-4 h-4" /> New Batch
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search medication..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-transparent focus:bg-white focus:border-blue-500 rounded-2xl text-sm outline-none transition-all font-bold"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
              <tr>
                <th className="px-8 py-5">Visual Identification</th>
                <th className="px-8 py-5">Medicine Info</th>
                <th className="px-8 py-5">Inventory Status</th>
                <th className="px-8 py-5">Financial Value</th>
                <th className="px-8 py-5">Clinical Expiry</th>
                <th className="px-8 py-5 text-right">Management</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredMeds.map((m) => (
                <tr key={m.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-8 py-4">
                    <div className="w-16 h-16 bg-slate-100 rounded-2xl border border-slate-200 overflow-hidden flex items-center justify-center relative">
                      {m.image ? (
                        <img src={m.image} alt={m.name} className="w-full h-full object-cover" />
                      ) : (
                        <ImageIcon className="w-6 h-6 text-slate-300" />
                      )}
                    </div>
                  </td>
                  <td className="px-8 py-4">
                    <div className="font-black text-slate-900 text-lg leading-tight">{m.name}</div>
                    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{m.category}</div>
                  </td>
                  <td className="px-8 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-24 bg-slate-100 h-2 rounded-full overflow-hidden">
                        <div 
                          className={`h-full rounded-full transition-all ${m.stock < 10 ? 'bg-rose-500' : 'bg-emerald-500'}`} 
                          style={{width: `${Math.min(100, (m.stock/200)*100)}%`}} 
                        />
                      </div>
                      <span className={`font-black text-sm ${m.stock < 10 ? 'text-rose-600' : 'text-slate-700'}`}>{m.stock}</span>
                      {m.stock < 10 && <AlertTriangle className="w-4 h-4 text-rose-500 animate-pulse" />}
                    </div>
                  </td>
                  <td className="px-8 py-4 text-sm font-black text-slate-900">${m.price.toFixed(2)}</td>
                  <td className="px-8 py-4">
                    <span className="px-3 py-1.5 bg-slate-100 rounded-xl text-[10px] font-black text-slate-500 uppercase tracking-widest border border-slate-200">
                      {m.expiryDate}
                    </span>
                  </td>
                  <td className="px-8 py-4 text-right">
                    <button onClick={() => handleDelete(m.id)} className="p-3 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-2xl transition-all">
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center z-[100] p-4 animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] w-full max-w-xl overflow-hidden shadow-2xl relative">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-black text-slate-900 tracking-tight">Add Medical Product</h2>
                <p className="text-sm text-slate-500 font-medium">Provision new stock batches to the repository.</p>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X className="w-6 h-6" /></button>
            </div>

            <form onSubmit={handleAdd} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Image Picker */}
                <div className="col-span-1 md:col-span-2 flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 rounded-[2rem] bg-slate-50 group hover:border-blue-400 transition-all cursor-pointer relative overflow-hidden">
                  <input 
                    type="file" 
                    accept="image/*" 
                    onChange={handleImageUpload} 
                    className="absolute inset-0 opacity-0 cursor-pointer z-10"
                  />
                  {newMed.image ? (
                    <img src={newMed.image} className="w-full h-48 object-cover rounded-2xl" alt="Preview" />
                  ) : (
                    <div className="flex flex-col items-center gap-2">
                      <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-slate-400 shadow-sm group-hover:text-blue-500 transition-colors">
                        <Camera className="w-6 h-6" />
                      </div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Attach Product Visual</p>
                    </div>
                  )}
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Product Designation</label>
                  <input required placeholder="e.g. Paracetamol" value={newMed.name} onChange={e => setNewMed({...newMed, name: e.target.value})} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Category Batch</label>
                  <input placeholder="Antibiotic, Painkiller..." value={newMed.category} onChange={e => setNewMed({...newMed, category: e.target.value})} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Stock Quantity</label>
                  <input required type="number" placeholder="0" value={newMed.stock} onChange={e => setNewMed({...newMed, stock: e.target.value})} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Unit Value (USD)</label>
                  <input required type="number" step="0.01" placeholder="0.00" value={newMed.price} onChange={e => setNewMed({...newMed, price: e.target.value})} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" />
                </div>

                <div className="col-span-1 md:col-span-2 space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Clinical Expiry Date</label>
                  <input required type="date" value={newMed.expiry} onChange={e => setNewMed({...newMed, expiry: e.target.value})} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" />
                </div>
              </div>

              <div className="pt-4">
                <button type="submit" className="w-full py-5 bg-emerald-600 text-white font-black rounded-[1.5rem] hover:bg-emerald-700 shadow-2xl shadow-emerald-600/30 transition-all uppercase tracking-[0.2em] text-[10px]">Add to Clinical Inventory</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

