  const handlePrint = () => {
    window.print();
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('invoice-content');
    const opt = {
      margin: 0.2,
      filename: `Dhool_Invoice_${transactionId}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };
    if (typeof html2pdf !== 'undefined') html2pdf().set(opt).from(element).save();
  };

  return (
    <div className="fixed inset-0 bg-black/70 z-[60] flex items-center justify-center p-4 backdrop-blur-sm print:bg-white print:p-0 print:static">
      <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl overflow-hidden print:shadow-none print:w-full print:max-w-none animate-in zoom-in duration-300">

        <div id="invoice-content" className="p-8 text-slate-800 font-mono text-xs bg-white">
          <div className="flex flex-col items-center justify-center mb-6 border-b-2 border-dashed border-slate-200 pb-6">
            <div className="bg-slate-50 p-2 rounded-2xl mb-3">
              <DhoolLogo className="w-14 h-14" />
            </div>
            <h1 className="text-3xl font-black text-blue-700 tracking-tighter leading-none mb-1">DHOOL</h1>
            <p className="text-xs font-bold text-emerald-500 uppercase tracking-[0.3em] leading-none mb-2">Dental Clinic</p>
            <p className="text-[9px] text-slate-400 uppercase tracking-widest italic text-center opacity-70">"YOUR SMILE IS OUR MISSION"</p>
          </div>

          <div className="mb-6 space-y-1 opacity-80">
            <div className="flex justify-between"><span>Date:</span> <span className="font-bold">{date}</span></div>
            <div className="flex justify-between"><span>ID:</span> <span className="font-bold">#{transactionId}</span></div>
            <div className="flex justify-between"><span>Method:</span> <span className="font-bold">{method}</span></div>
