      expiryDate: newMed.expiry,
      category: newMed.category,
      image: newMed.image
    };
    setInventory(prev => [...prev, m]);
    setIsModalOpen(false);
    setNewMed({ name: '', stock: '', price: '', expiry: '', category: 'General', image: '' });
