const DAFTRA_API_KEY = 'abdce1a8aa82aa01f0b9454e4dc581daf6799eb2';
const DAFTRA_API_ID = '1433989';
// Note: Replace 'your-subdomain' with your actual Daftra subdomain
const BASE_URL = 'https://dhool.daftra.com/api2'; 

export const daftraApi = {
  /**
   * Fetch all clients (Patients) from Daftra
   */
  getPatients: async () => {
    try {
      const response = await fetch(`${BASE_URL}/clients`, {
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        }
      });
      if (!response.ok) throw new Error('Daftra connection failed');
      return await response.json();
    } catch (error) {
      console.error('Daftra API Error:', error);
      return null;
    }
  },

  /**
   * Fetch invoices from Daftra
   */
  getInvoices: async () => {
    try {
      const response = await fetch(`${BASE_URL}/invoices`, {
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        }
      });
      if (!response.ok) throw new Error('Daftra connection failed');
      return await response.json();
    } catch (error) {
      console.error('Daftra API Error:', error);
      return null;
    }
  },

  /**
   * Create a new invoice in Daftra after a sale in Dhool Clinic
   */
  createInvoice: async (invoiceData: any) => {
    try {
      const response = await fetch(`${BASE_URL}/invoices`, {
        method: 'POST',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(invoiceData)
      });
      return await response.json();
    } catch (error) {
      console.error('Daftra Invoice Error:', error);
      return null;
    }
  }
};

