          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg"><Menu className="w-5 h-5 text-slate-600" /></button>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-3 bg-slate-50 p-1.5 px-3 rounded-full border border-slate-200">
              <img src="https://picsum.photos/seed/dentist/40/40" className="w-6 h-6 rounded-full" />
              <span className="text-xs font-black text-slate-700">Dr. Ahmed</span>
            </div>
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-6 md:p-8">
          {activeView === 'dashboard' && <DashboardView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} />}
          {activeView === 'patients' && (
            <PatientsView 
              patients={patients} 
              addPatient={async (p) => {
                const newP = await supabaseService.insertPatient(p);
                setPatients([newP, ...patients]);
              }} 
              patientHistory={patientHistory} 
              addPatientHistory={async (h) => {
                const newH = await supabaseService.insertHistory(h);
                setPatientHistory([newH, ...patientHistory]);
              }} 
              prescriptions={prescriptions} 
              addPrescription={async (pr) => setPrescriptions([pr, ...prescriptions])} 
              user={users[0]} 
              t={t} 
            />
          )}
          {activeView === 'pharmacy' && (
            <PharmacyView 
              inventory={inventory} 
              setInventory={async (updater) => {
                // Simplified for direct Supabase call
                if (typeof updater === 'function') {
                  // If child component uses callback setInventory(prev => ...)
                }
              }} 
              onAddMedicine={async (m) => {
                const newM = await supabaseService.insertMedicine(m);
                setInventory(prev => [newM, ...prev]);
              }}
              onDeleteMedicine={async (id) => {
                setInventory(prev => prev.filter(i => i.id !== id));
              }}
            />
          )}
          {activeView === 'pos' && <POSView products={inventory} processSale={async (items, total, method) => {
             // 1. Update Inventory in Supabase
             for (const item of items) {
                const p = inventory.find(x => x.id === item.id);
                if (p) await supabaseService.updateStock(item.id, p.stock - item.quantity);
             }
             // 2. Create Invoice in Supabase
             const inv: Invoice = {
               id: `INV-${Date.now().toString().slice(-6)}`,
               patientName: 'Walk-in',
               date: new Date().toLocaleDateString(),
               amount: total,
               status: 'Paid',
               type: 'Pharmacy'
             };
             await supabaseService.insertInvoice(inv);
             // 3. Create Invoice in Daftra
             await daftraApi.createInvoice({ amount: total, notes: 'Dhool POS' });
             loadData(); // Refresh all
          }} t={t} />}
          {activeView === 'appointments' && (
            <AppointmentsView 
              appointments={appointments} 
              patients={patients}
              setAppointments={setAppointments}
              onAddAppointment={async (apt) => {
                const newApt = await supabaseService.insertAppointment(apt);
                setAppointments([newApt, ...appointments]);
              }}
            />
          )}
          {activeView === 'billing' && <BillingView invoices={invoices} />}
          {activeView === 'reports' && <ReportsView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} expenses={expenses} salaries={salaries} />}
          {activeView === 'ai-assistant' && <AIAssistantView />}
          {activeView === 'users' && <UsersView appUsers={users} addUser={async u => ({success: true})} deleteUser={async id => {}} t={t} currentUser={users[0]} />}
        </section>
      </main>
    </div>
  );
};

