import ExpensesView from './views/ExpensesView';
import SalariesView from './views/SalariesView';
import UsersView from './views/UsersView';
import ReportsView from './views/ReportsView';
import AIAssistantView from './views/AIAssistantView';
import { daftraApi } from './services/daftraService';
import { supabaseService } from './services/supabaseService';

export const DhoolLogo = ({ className = "w-10 h-10" }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className} fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 15C38 15 28 22 25 35C22 55 35 70 45 85C47 88 50 92 50 95C50 92 53 88 55 85C65 70 78 55 75 35C72 22 62 15 50 15Z" stroke="url(#logoGrad)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M40 45C45 52 55 52 60 45" stroke="url(#logoGrad)" strokeWidth="4" strokeLinecap="round" opacity="0.6" />
    <defs>
      <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#0056b3" />
        <stop offset="100%" stopColor="#32cd32" />
      </linearGradient>
    </defs>
  </svg>
);

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'syncing'>('connected');

  // --- STATE ---
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [prescriptions, setPrescriptions] = useState<Prescription[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([
    { id: '1', name: 'Dr. Ahmed', role: 'Admin', email: 'admin@dhool.com', status: 'Active' }
  ]);

  // Initial Load
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setDbStatus('syncing');
    try {
      const [p, m, a, i] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices()
      ]);
      setPatients(p || []);
      setInventory(m || []);
      setAppointments(a || []);
      setInvoices(i || []);
      setDbStatus('connected');
    } catch (error) {
      setDbStatus('error');
    }
  };

  const syncWithDaftra = async () => {
    setIsSyncing(true);
    try {
      // Create a test client in Daftra to verify link
      await daftraApi.getPatients();
      setIsSyncing(false);
      alert('Daftra Sync Completed!');
    } catch (e) {
      setIsSyncing(false);
      alert('Daftra Sync Failed');
    }
  };

  const t = (key: string) => {
    const dict: Record<string, string> = {
      pos: 'POS Terminal',
      stock: 'Stock',
      patients: 'Bukaannada'
    };
    return dict[key] || key;
  };

  // Nav Items
  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'patients', label: 'Patients', icon: Users },
    { id: 'appointments', label: 'Appointments', icon: Calendar },
    { id: 'pos', label: 'Point of Sale', icon: ShoppingCart },
    { id: 'pharmacy', label: 'Pharmacy', icon: Package },
    { id: 'billing', label: 'Invoices', icon: Receipt },
    { id: 'reports', label: 'Reports', icon: BarChart3 },
    { id: 'ai-assistant', label: 'AI Assistant', icon: Bot },
    { id: 'users', label: 'Personnel', icon: UserCircle },
  ];

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900 selection:bg-blue-100">
      {/* Sidebar */}
      <aside className={`bg-[#0a1120] text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col border-r border-white/5`}>
        <div className="p-6 flex flex-col items-center gap-2">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-xl"><DhoolLogo /></div>
            {isSidebarOpen && <span className="text-xl font-black text-blue-500 uppercase tracking-tighter">DHOOL</span>}
          </div>
        </div>

        <nav className="flex-1 mt-6 px-3">
          {navItems.map((item) => (
            <button
              key={item.id}
              // Fixed: Removed explicit union in type cast as ViewType now correctly includes 'ai-assistant'
              onClick={() => setActiveView(item.id as ViewType)}
              className={`w-full flex items-center gap-4 px-4 py-3.5 rounded-2xl mb-1 transition-all ${
                activeView === item.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30' : 'text-slate-500 hover:text-white hover:bg-white/5'
              }`}
            >
              <item.icon className="w-5 h-5" />
              {isSidebarOpen && <span className="text-sm font-bold">{item.label}</span>}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-white/5 space-y-2">
          <div className="flex items-center gap-2 px-4 py-2 text-[10px] font-black uppercase">
            <Database className={`w-3 h-3 ${dbStatus === 'connected' ? 'text-emerald-500' : 'text-rose-500'}`} />
            {isSidebarOpen && <span className={dbStatus === 'connected' ? 'text-emerald-500' : 'text-rose-500'}>{dbStatus}</span>}
          </div>
          <button onClick={syncWithDaftra} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white transition-all">
            <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
            {isSidebarOpen && <span className="text-xs font-black uppercase">Daftra Sync</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6">
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-100 rounded-lg"><Menu className="w-5 h-5 text-slate-600" /></button>
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-3 bg-slate-50 p-1.5 px-3 rounded-full border border-slate-200">
              <img src="https://picsum.photos/seed/dentist/40/40" className="w-6 h-6 rounded-full" />
              <span className="text-xs font-black text-slate-700">Dr. Ahmed</span>
            </div>
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-6 md:p-8">
          {activeView === 'dashboard' && <DashboardView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} />}
          {activeView === 'patients' && (
            <PatientsView 
              patients={patients} 
              addPatient={async (p) => {
                const newP = await supabaseService.insertPatient(p);
                setPatients([newP, ...patients]);
              }} 
              patientHistory={patientHistory} 
              addPatientHistory={async (h) => {
                const newH = await supabaseService.insertHistory(h);
                setPatientHistory([newH, ...patientHistory]);
              }} 
              prescriptions={prescriptions} 
              addPrescription={async (pr) => setPrescriptions([pr, ...prescriptions])} 
              user={users[0]} 
              t={t} 
            />
          )}
          {activeView === 'pharmacy' && (
            <PharmacyView 
              inventory={inventory} 
              setInventory={async (updater) => {
                // Simplified for direct Supabase call
                if (typeof updater === 'function') {
                  // If child component uses callback setInventory(prev => ...)
                }
              }} 
              onAddMedicine={async (m) => {
                const newM = await supabaseService.insertMedicine(m);
                setInventory(prev => [newM, ...prev]);
              }}
              onDeleteMedicine={async (id) => {
                setInventory(prev => prev.filter(i => i.id !== id));
              }}
            />
          )}
          {activeView === 'pos' && <POSView products={inventory} processSale={async (items, total, method) => {
             // 1. Update Inventory in Supabase
             for (const item of items) {
                const p = inventory.find(x => x.id === item.id);
                if (p) await supabaseService.updateStock(item.id, p.stock - item.quantity);
             }
             // 2. Create Invoice in Supabase
             const inv: Invoice = {
               id: `INV-${Date.now().toString().slice(-6)}`,
               patientName: 'Walk-in',
               date: new Date().toLocaleDateString(),
               amount: total,
               status: 'Paid',
               type: 'Pharmacy'
             };
             await supabaseService.insertInvoice(inv);
             // 3. Create Invoice in Daftra
             await daftraApi.createInvoice({ amount: total, notes: 'Dhool POS' });
             loadData(); // Refresh all
          }} t={t} />}
          {activeView === 'appointments' && (
            <AppointmentsView 
              appointments={appointments} 
              patients={patients}
              setAppointments={setAppointments}
              onAddAppointment={async (apt) => {
                const newApt = await supabaseService.insertAppointment(apt);
                setAppointments([newApt, ...appointments]);
              }}
            />
          )}
          {activeView === 'billing' && <BillingView invoices={invoices} />}
          {activeView === 'reports' && <ReportsView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} expenses={expenses} salaries={salaries} />}
          {activeView === 'ai-assistant' && <AIAssistantView />}
          {activeView === 'users' && <UsersView appUsers={users} addUser={async u => ({success: true})} deleteUser={async id => {}} t={t} currentUser={users[0]} />}
        </section>
      </main>
    </div>
  );
};

export default App;

