import { supabase } from '../lib/supabase';
import { Patient, Medicine, Appointment, Invoice, PatientHistory, Prescription } from '../types';

export const supabaseService = {
  // --- PATIENTS ---
  getPatients: async () => {
    const { data, error } = await supabase.from('patients').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    return data as Patient[];
  },
  insertPatient: async (patient: Patient) => {
    // We omit created_at so Supabase can handle it
    const { data, error } = await supabase.from('patients').insert([patient]).select();
    if (error) throw error;
    return data[0];
  },

  // --- INVENTORY ---
  getInventory: async () => {
    const { data, error } = await supabase.from('inventory').select('*').order('name');
    if (error) throw error;
    return data as Medicine[];
  },
  updateStock: async (id: string, newStock: number) => {
    const { error } = await supabase.from('inventory').update({ stock: newStock }).eq('id', id);
    if (error) throw error;
  },
  insertMedicine: async (medicine: Medicine) => {
    const { data, error } = await supabase.from('inventory').insert([medicine]).select();
    if (error) throw error;
    return data[0];
  },

  // --- APPOINTMENTS ---
  getAppointments: async () => {
    const { data, error } = await supabase.from('appointments').select('*').order('date', { ascending: true });
    if (error) throw error;
    return data as Appointment[];
  },
  insertAppointment: async (appointment: Appointment) => {
    const { data, error } = await supabase.from('appointments').insert([appointment]).select();
    if (error) throw error;
    return data[0];
  },

  // --- BILLING ---
  getInvoices: async () => {
    const { data, error } = await supabase.from('invoices').select('*').order('date', { ascending: false });
    if (error) throw error;
    return data as Invoice[];
  },
  insertInvoice: async (invoice: Invoice) => {
    const { data, error } = await supabase.from('invoices').insert([invoice]).select();
    if (error) throw error;
    return data[0];
  },

  // --- HISTORY & PRESCRIPTIONS ---
  getHistory: async (patientId: string) => {
    const { data, error } = await supabase.from('patient_history').select('*').eq('patientId', patientId);
    if (error) throw error;
    return data as PatientHistory[];
  },
  insertHistory: async (history: PatientHistory) => {
    const { data, error } = await supabase.from('patient_history').insert([history]).select();
    if (error) throw error;
    return data[0];
  }
};

/**
 * Daftra API Service for Dhool Dental Clinic
 * Credentials provided by user:
 * ID: 1433989, Name: internalApi, Key: abdce1a8aa82aa01f0b9454e4dc581daf6799eb2
 */

const DAFTRA_API_KEY = 'abdce1a8aa82aa01f0b9454e4dc581daf6799eb2';
// Correct URL structure for Daftra API v2
const BASE_URL = 'https://dhool.daftra.com/api2'; 

export const daftraApi = {
  /**
   * Fetch all clients (Patients) from Daftra
   */
  getPatients: async () => {
    try {
      const response = await fetch(`${BASE_URL}/clients`, {
        method: 'GET',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        const errorBody = await response.text();
        console.error('Daftra API Details:', errorBody);
        throw new Error(`Daftra failed: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error('Daftra Connection Error:', error);
      // Return empty array to prevent app crash
      return { data: [] };
    }
  },

  /**
   * Create a new invoice in Daftra
   */
  createInvoice: async (invoiceData: { amount: number; notes: string; client_id?: number }) => {
    try {
      const response = await fetch(`${BASE_URL}/invoices`, {
        method: 'POST',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          Invoice: {
            client_id: invoiceData.client_id || 1, // Default to first client if not specified
            notes: invoiceData.notes,
            invoice_items: [
              {
                item: "Clinical Service / Pharmacy Product",
                unit_price: invoiceData.amount,
                quantity: 1
              }
            ]
          }
        })
      });

      return await response.json();
    } catch (error) {
      console.error('Daftra Invoice Error:', error);
      return null;
    }
  }
};

