const DAFTRA_API_KEY = 'abdce1a8aa82aa01f0b9454e4dc581daf6799eb2';
// Correct URL structure for Daftra API v2
const BASE_URL = 'https://dhool.daftra.com/api2'; 

export const daftraApi = {
  /**
   * Fetch all clients (Patients) from Daftra
   */
  getPatients: async () => {
    try {
      const response = await fetch(`${BASE_URL}/clients`, {
        method: 'GET',
        headers: {
          'apikey': DAFTRA_API_KEY,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        const errorText = await response.text();
        console.error('Daftra API Error:', errorText);
        throw new Error(`Daftra Authorization Failed (401). Check API Key.`);
      }

      return await response.json();
    } catch (error: any) {
      console.error('Daftra Connection Error:', error.message || error);
      return { data: [] };
    }
  },

  /**
   * Create a new invoice in Daftra
   */
  createInvoice: async (invoiceData: { amount: number; notes: string; client_id?: number }) => {
    try {
      const response = await fetch(`${BASE_URL}/invoices`, {
        method: 'POST',
        headers: {
          'apikey': DAFTRA_API_KEY,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          Invoice: {
            client_id: invoiceData.client_id || 1,
            notes: invoiceData.notes,
            invoice_items: [
              {
                item: "Clinical Service / Pharmacy Product",
                unit_price: invoiceData.amount,
                quantity: 1
              }
            ]
          }
        })
      });

      if (!response.ok) {
        const err = await response.text();
        console.error('Invoice Creation Error:', err);
        return null;
      }
      return await response.json();
    } catch (error: any) {
      console.error('Daftra Invoice Exception:', error.message || error);
      return null;
    }
  }
};

