/**
 * Daftra API Service for Dhool Dental Clinic
 * Client ID: 1
 * Client Secret: jCfy6cMh1X6NTxR3OWLuvEFa0si5uZKr05UeoAEs
 */

const DAFTRA_API_KEY = 'jCfy6cMh1X6NTxR3OWLuvEFa0si5uZKr05UeoAEs';
const BASE_URL = 'https://dhool.daftra.com/api2'; 

export const daftraApi = {
  /**
   * Fetch all clients (Patients) from Daftra
   */
  getPatients: async () => {
    try {
      const response = await fetch(`${BASE_URL}/clients`, {
        method: 'GET',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        }
      });

      const responseData = await response.json();

      if (!response.ok) {
        const errorMsg = responseData.message || responseData.result || 'Unauthorized';
        console.error('Daftra API Error Details:', JSON.stringify(responseData));
        throw new Error(`Daftra Error: ${errorMsg} (Code: ${response.status})`);
      }

      return responseData;
    } catch (error: any) {
      console.error('Daftra Connection Exception:', error.message);
      throw error;
    }
  },

  /**
   * Create a new invoice in Daftra
   */
  createInvoice: async (invoiceData: { amount: number; notes: string; client_id?: number }) => {
    try {
      const response = await fetch(`${BASE_URL}/invoices`, {
        method: 'POST',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          Invoice: {
            client_id: invoiceData.client_id || 1,
            notes: invoiceData.notes,
            invoice_items: [
              {
                item: "Clinical Service / Pharmacy Product",
                unit_price: invoiceData.amount,
                quantity: 1
              }
            ]
          }
        })
      });

      const result = await response.json();
      if (!response.ok) {
        console.error('Invoice Creation Failed:', JSON.stringify(result));
        return null;
      }
      return result;
    } catch (error: any) {
      console.error('Daftra Invoice Exception:', error.message);
      return null;
    }
  }
};

