          {activeView === 'pos' && <POSView products={inventory} processSale={async (items, total, method) => {
             for (const item of items) {
                const p = inventory.find(x => x.id === item.id);
                if (p) await supabaseService.updateStock(item.id, p.stock - item.quantity);
             }
             const inv: Invoice = {
               id: `INV-${Date.now().toString().slice(-6)}`,
               patientName: 'Walk-in',
               date: new Date().toLocaleDateString(),
               amount: total,
               status: 'Paid',
               type: 'Pharmacy'
             };
             await supabaseService.insertInvoice(inv);
             await daftraApi.createInvoice({ amount: total, notes: 'Dhool POS Sales' });
             loadData();
          }} t={t} />}
          {activeView === 'appointments' && (
            <AppointmentsView 
              appointments={appointments} 
              patients={patients}
              setAppointments={setAppointments}
              onAddAppointment={async (apt) => {
                const newApt = await supabaseService.insertAppointment(apt);
                setAppointments([newApt, ...appointments]);
              }}
            />
          )}
          {activeView === 'billing' && <BillingView invoices={invoices} />}
          {activeView === 'reports' && <ReportsView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} expenses={expenses} salaries={salaries} />}
          {activeView === 'settings' && <SettingsView user={users[0]} language={language} setLanguage={setLanguage} t={t} updateCurrentUser={updateCurrentUser} />}
          {activeView === 'users' && <UsersView appUsers={users} addUser={addUser} deleteUser={deleteUser} t={t} currentUser={users[0]} />}
        </section>
      </main>
    </div>
  );
};

