import React, { useState } from 'react';
import { ShoppingCart, ShoppingBag, Trash2, ChevronDown, Package, Percent, Tag, DollarSign } from 'lucide-react';
import { Medicine, CartItem, Product } from '../types';
import { Invoice } from '../components/Invoice';

interface Props {
  products: Product[];
  processSale: (items: { id: string; quantity: number }[], total: number, method: string, discount: number) => void;
  t: (key: string) => string;
}

const POSView: React.FC<Props> = ({ products, processSale, t }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showCheckout, setShowCheckout] = useState(false);
  const [discount, setDiscount] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'percent' | 'flat'>('percent');

  // Invoice State
  const [showInvoice, setShowInvoice] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<{
    items: CartItem[];
    total: number;
    id: string;
    method: string;
    date: string;
    discount: number;
  } | null>(null);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return;
    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) return;
      setCart(cart.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const calculateSubtotal = () => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const calculateTotal = () => {
    const sub = calculateSubtotal();
    if (discountType === 'percent') {
      return sub * (1 - discount / 100);
    }
    return Math.max(0, sub - discount);
  };

  const handleCheckout = (method: 'Cash' | 'Zaad' | 'Bank') => {
    if (cart.length === 0) return;

    const finalTotal = calculateTotal();
    const transactionId = Math.floor(Math.random() * 900000 + 100000).toString();
    const date = new Date().toLocaleString();

    processSale(cart.map(i => ({ id: i.id, quantity: i.quantity })), finalTotal, method, discount);

    setLastTransaction({
      items: [...cart],
      total: finalTotal,
      id: transactionId,
      method,
      date,
      discount: discount
    });
    setShowInvoice(true);

    setCart([]);
    setDiscount(0);
    setShowCheckout(false);
  };

  return (
    <div className="h-full flex flex-col lg:flex-row bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden relative">

      {showInvoice && lastTransaction && (
        <Invoice 
          items={lastTransaction.items}
          total={lastTransaction.total}
          transactionId={lastTransaction.id}
          date={lastTransaction.date}
          method={lastTransaction.method}
          onClose={() => setShowInvoice(false)}
          t={t}
        />
      )}

      {/* Product Area */}
      <div className="flex-1 flex flex-col min-w-0">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
           <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
                 <ShoppingCart className="w-5 h-5" />
              </div>
              <h2 className="text-xl font-black text-slate-900 tracking-tight">Point of Sale</h2>
           </div>
           <div className="flex items-center gap-2">
              <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest bg-slate-50 px-3 py-1.5 rounded-xl border border-slate-100">{products.length} Items In Stock</span>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4 no-scrollbar bg-slate-50/50">
          {products.map(product => (
            <div 
              key={product.id} 
              onClick={() => addToCart(product)}
              className={`bg-white p-4 rounded-3xl border border-slate-200 cursor-pointer transition-all active:scale-95 flex flex-col group ${product.stock === 0 ? 'opacity-50 grayscale pointer-events-none' : 'hover:shadow-xl hover:border-blue-500'}`}
            >
              <div className="h-24 bg-slate-50 rounded-2xl mb-4 flex items-center justify-center text-slate-300 relative overflow-hidden group-hover:bg-blue-50 transition-colors">
                 <Package className="w-8 h-8 group-hover:scale-125 transition-transform" />
                 {product.stock <= 5 && product.stock > 0 && (
                   <div className="absolute top-2 right-2 bg-amber-500 text-white text-[8px] font-black px-2 py-1 rounded-full uppercase">Low Stock</div>
                 )}
              </div>
              <h3 className="font-black text-slate-800 text-xs mb-1 truncate">{product.name}</h3>
              <div className="flex justify-between items-end mt-auto">
                 <span className="text-blue-600 font-black text-lg">${product.price.toFixed(2)}</span>
                 <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{product.stock} units</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Professional Cart Sidebar */}
      <div className="w-full lg:w-[400px] bg-white border-l border-slate-100 flex flex-col shadow-2xl lg:shadow-none">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
           <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Order Summary</h3>
           <div className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black">{cart.length}</div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 no-scrollbar">
          {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-20 text-center">
               <ShoppingBag className="w-24 h-24 mb-4 stroke-1" />
               <p className="font-black uppercase tracking-widest text-[10px]">Your basket is empty</p>
             </div>
          ) : (
            cart.map((item, idx) => (
              <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 animate-in slide-in-from-right-4">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center font-black text-blue-600 border border-slate-200">x{item.quantity}</div>
                    <div>
                       <p className="font-black text-slate-900 text-xs truncate w-32">{item.name}</p>
                       <p className="text-[10px] font-black text-blue-500">${(item.price * item.quantity).toFixed(2)}</p>
                    </div>
                 </div>
                 <button onClick={() => removeFromCart(item.id)} className="p-2 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
              </div>
            ))
          )}
        </div>

        {/* Footer with Discount Controls */}
        <div className="p-8 bg-slate-50 border-t border-slate-200 space-y-6">

          {/* Discount Section */}
          <div className="space-y-3">
             <div className="flex items-center justify-between">
                <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                   <Percent className="w-3 h-3" /> Apply Discount
                </span>
                <div className="flex bg-white rounded-lg p-1 border border-slate-200">
                   <button onClick={() => setDiscountType('percent')} className={`px-3 py-1 rounded-md text-[10px] font-black transition-all ${discountType === 'percent' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>%</button>
                   <button onClick={() => setDiscountType('flat')} className={`px-3 py-1 rounded-md text-[10px] font-black transition-all ${discountType === 'flat' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>$</button>
                </div>
             </div>
             <div className="relative">
                <input 
                   type="number" 
                   value={discount} 
                   onChange={(e) => setDiscount(Math.max(0, parseFloat(e.target.value) || 0))} 
                   className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-black outline-none focus:border-blue-500 transition-all pl-10"
                   placeholder="Enter discount amount..."
                />
                <Tag className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
             </div>
          </div>

          <div className="space-y-2 border-t border-slate-200 pt-6">
             <div className="flex justify-between text-xs font-bold text-slate-400">
                <span>Subtotal</span>
                <span>${calculateSubtotal().toFixed(2)}</span>
             </div>
             {discount > 0 && (
               <div className="flex justify-between text-xs font-bold text-rose-500">
                  <span>Discount ({discountType === 'percent' ? `${discount}%` : `$${discount}`})</span>
                  <span>-${(calculateSubtotal() - calculateTotal()).toFixed(2)}</span>
               </div>
             )}
             <div className="flex justify-between items-center mt-2">
                <span className="text-sm font-black text-slate-900 uppercase tracking-widest">Grand Total</span>
                <span className="text-3xl font-black text-blue-700 tracking-tighter">${calculateTotal().toFixed(2)}</span>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-3 pt-4">
             <button 
                onClick={() => handleCheckout('Cash')}
                disabled={cart.length === 0}
                className="py-4 bg-white border-2 border-slate-200 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:border-blue-600 hover:text-blue-600 transition-all disabled:opacity-30 flex items-center justify-center gap-2"
             >
                <DollarSign className="w-3 h-3" /> Cash
             </button>
             <button 
                onClick={() => handleCheckout('Zaad')}
                disabled={cart.length === 0}
                className="py-4 bg-blue-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-700 shadow-xl shadow-blue-600/20 transition-all disabled:opacity-30"
             >
                Zaad / Bank
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default POSView;

import React from 'react';
import { CartItem } from '../types';
import { DhoolLogo } from '../App';

interface InvoiceProps {
  items: CartItem[];
  total: number;
  date: string;
  transactionId: string;
  method: string;
  onClose: () => void;
  t: (key: string) => string;
}

declare const html2pdf: any;

export const Invoice: React.FC<InvoiceProps> = ({ items, total, date, transactionId, method, onClose, t }) => {
  const handlePrint = () => {
    window.print();
  };

  const handleDownloadPDF = () => {
    const element = document.getElementById('invoice-content');
    const opt = {
      margin: 0.2,
      filename: `Dhool_Invoice_${transactionId}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };
    if (typeof html2pdf !== 'undefined') html2pdf().set(opt).from(element).save();
  };

  const subtotal = items.reduce((acc, item) => acc + (item.price * item.quantity), 0);
  const discountAmount = subtotal - total;

  return (
    <div className="fixed inset-0 bg-black/70 z-[60] flex items-center justify-center p-4 backdrop-blur-sm print:bg-white print:p-0 print:static">
      <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl overflow-hidden print:shadow-none print:w-full print:max-w-none animate-in zoom-in duration-300">

        <div id="invoice-content" className="p-8 text-slate-800 font-mono text-xs bg-white">
          <div className="flex flex-col items-center justify-center mb-6 border-b-2 border-dashed border-slate-200 pb-6">
            <div className="bg-slate-50 p-2 rounded-2xl mb-3">
              <DhoolLogo className="w-14 h-14" />
            </div>
            <h1 className="text-3xl font-black text-blue-700 tracking-tighter leading-none mb-1">DHOOL</h1>
            <p className="text-xs font-bold text-emerald-500 uppercase tracking-[0.3em] leading-none mb-2">Dental Clinic</p>
            <p className="text-[9px] text-slate-400 uppercase tracking-widest italic text-center opacity-70">"YOUR SMILE IS OUR MISSION"</p>
          </div>

          <div className="mb-6 space-y-1 opacity-80">
            <div className="flex justify-between"><span>Date:</span> <span className="font-bold">{date}</span></div>
            <div className="flex justify-between"><span>ID:</span> <span className="font-bold">#{transactionId}</span></div>
            <div className="flex justify-between"><span>Method:</span> <span className="font-bold">{method}</span></div>
          </div>

          <table className="w-full mb-6 text-[11px]">
            <thead>
              <tr className="border-b border-slate-200 text-left">
                <th className="py-2">Item</th>
                <th className="py-2 text-center">Qty</th>
                <th className="py-2 text-right">Price</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-dashed divide-slate-100">
              {items.map((item, index) => (
                <tr key={index}>
                  <td className="py-3 font-bold">{item.name}</td>
                  <td className="py-3 text-center">x{item.quantity}</td>
                  <td className="py-3 text-right">${(item.price * item.quantity).toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="border-t-2 border-dashed border-slate-200 pt-4 mb-8 space-y-2">
            <div className="flex justify-between text-slate-400">
              <span className="font-bold uppercase tracking-widest">Subtotal</span>
              <span className="font-black">${subtotal.toFixed(2)}</span>
            </div>
            {discountAmount > 0 && (
              <div className="flex justify-between text-rose-500">
                <span className="font-bold uppercase tracking-widest">Discount</span>
                <span className="font-black">-${discountAmount.toFixed(2)}</span>
              </div>
            )}
            <div className="flex justify-between items-center pt-2">
              <span className="text-sm font-bold uppercase tracking-widest text-slate-900">Total</span>
              <span className="text-2xl font-black text-blue-700">${total.toFixed(2)}</span>
            </div>
          </div>

          <div className="text-center space-y-1 opacity-50">
            <p className="text-[10px] font-bold">Maka Al-Mukarama Rd, Mogadishu</p>
            <p className="text-[9px]">Mahadsanid, mar kale soo laabo!</p>
          </div>
        </div>

        <div className="p-6 bg-slate-50 flex gap-3 print:hidden border-t border-slate-100">
          <button onClick={onClose} className="flex-1 py-4 text-slate-500 font-black bg-white border border-slate-200 rounded-2xl hover:bg-slate-100 transition-all text-[10px] uppercase tracking-widest">Cancel</button>
          <button onClick={handleDownloadPDF} className="flex-1 py-4 text-white font-black bg-slate-900 rounded-2xl hover:bg-black transition-all text-[10px] uppercase tracking-widest">PDF</button>
          <button onClick={handlePrint} className="flex-1 py-4 text-white font-black bg-blue-600 rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-600/20 transition-all text-[10px] uppercase tracking-widest">Print</button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Users, Calendar, CreditCard, Menu, ChevronDown, ChevronRight,
  Package, Receipt, Wallet, UserCircle, BarChart3, ShoppingCart, RefreshCw, 
  Database, Settings as SettingsIcon, LogOut, Landmark, PlusSquare, List,
  Search, Bell
} from 'lucide-react';
import { 
  ViewType, Patient, Appointment, Medicine, Invoice, 
  Expense, Salary, StaffUser, Role, PatientHistory, Prescription
} from './types';
import DashboardView from './views/DashboardView';
import PatientsView from './views/PatientsView';
import AppointmentsView from './views/AppointmentsView';
import PharmacyView from './views/PharmacyView';
import POSView from './views/POSView';
import BillingView from './views/BillingView';
import ExpensesView from './views/ExpensesView';
import SalariesView from './views/SalariesView';
import UsersView from './views/UsersView';
import ReportsView from './views/ReportsView';
import SettingsView from './views/SettingsView';
import { daftraApi } from './services/daftraService';
import { supabaseService } from './services/supabaseService';

export const DhoolLogo = ({ className = "w-10 h-10" }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className} fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 15C38 15 28 22 25 35C22 55 35 70 45 85C47 88 50 92 50 95C50 92 53 88 55 85C65 70 78 55 75 35C72 22 62 15 50 15Z" stroke="url(#logoGrad)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M40 45C45 52 55 52 60 45" stroke="url(#logoGrad)" strokeWidth="4" strokeLinecap="round" opacity="0.6" />
    <defs>
      <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#0056b3" />
        <stop offset="100%" stopColor="#32cd32" />
      </linearGradient>
    </defs>
  </svg>
);

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [expandedGroups, setExpandedGroups] = useState<string[]>(['sales', 'clients']);
  const [isSyncing, setIsSyncing] = useState(false);
  const [dbStatus, setDbStatus] = useState<'connected' | 'error' | 'syncing'>('connected');
  const [language, setLanguage] = useState<'so' | 'en'>('en');

  // --- STATE ---
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [prescriptions, setPrescriptions] = useState<Prescription[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([
    { id: '1', name: 'Dr. Ahmed Osman', role: 'Admin', email: 'admin@dhool.com', status: 'Active', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Ahmed' }
  ]);

  const currentUser = users[0];

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setDbStatus('syncing');
    try {
      const [p, m, a, i] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices()
      ]);
      setPatients(p || []);
      setInventory(m || []);
      setAppointments(a || []);
      setInvoices(i || []);
      setDbStatus('connected');
    } catch (error: any) {
      console.error("Load Error:", error.message);
      setDbStatus('error');
    }
  };

  const syncWithDaftra = async () => {
    setIsSyncing(true);
    try {
      const result = await daftraApi.getPatients();
      setIsSyncing(false);
      if (result && result.data) alert('Daftra Sync Success!');
    } catch (e: any) {
      setIsSyncing(false);
      alert('Daftra Connection Failed: ' + e.message);
    }
  };

  const toggleGroup = (groupId: string) => {
    setExpandedGroups(prev => 
      prev.includes(groupId) ? prev.filter(g => g !== groupId) : [...prev, groupId]
    );
  };

  const t = (key: string) => {
    const dict: Record<string, any> = {
      en: {
        dashboard: 'Dashboard',
        sales: 'Sales',
        pos: 'POS Terminal',
        invoices: 'Manage Invoices',
        clients: 'Clients',
        patients: 'Manage Patients',
        add_patient: 'Add New Patient',
        finance: 'Finance',
        expenses: 'Expenses',
        treasury: 'Treasuries',
        reports: 'Reports',
        settings: 'Settings',
        admin: 'Personnel',
        inventory: 'Pharmacy Inventory',
        appointments: 'Appointments'
      }
    };
    return dict['en'][key] || key;
  };

  // RBAC: Check if role has access to view
  const canAccess = (view: ViewType) => {
    if (currentUser.role === 'Admin') return true;
    if (currentUser.role === 'Doctor') return ['dashboard', 'patients', 'appointments', 'pharmacy'].includes(view);
    if (currentUser.role === 'Accountant') return ['dashboard', 'invoices', 'expenses', 'reports', 'treasury'].includes(view);
    if (currentUser.role === 'Staff') return ['dashboard', 'pos', 'appointments', 'patients'].includes(view);
    return false;
  };

  const NavGroup = ({ id, label, icon: Icon, children }: { id: string, label: string, icon: any, children: React.ReactNode }) => {
    const isExpanded = expandedGroups.includes(id);
    return (
      <div className="mb-2">
        <button 
          onClick={() => toggleGroup(id)}
          className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${isExpanded ? 'bg-white/5 text-blue-400' : 'text-slate-400 hover:text-white'}`}
        >
          <div className="flex items-center gap-3">
            <Icon className="w-5 h-5" />
            {isSidebarOpen && <span className="text-sm font-bold uppercase tracking-wider">{label}</span>}
          </div>
          {isSidebarOpen && (isExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />)}
        </button>
        {isExpanded && isSidebarOpen && (
          <div className="mt-1 ml-4 border-l border-white/5 pl-4 space-y-1 animate-in slide-in-from-left-2">
            {children}
          </div>
        )}
      </div>
    );
  };

  const NavItem = ({ id, label, icon: Icon, view }: { id: string, label: string, icon?: any, view: ViewType }) => (
    <button
      onClick={() => canAccess(view) && setActiveView(view)}
      className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold transition-all ${
        activeView === view ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30' : 'text-slate-500 hover:text-white'
      } ${!canAccess(view) ? 'opacity-30 cursor-not-allowed' : ''}`}
    >
      {Icon && <Icon className="w-4 h-4" />}
      <span>{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900 selection:bg-blue-100">
      <aside className={`bg-[#0a1120] text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col border-r border-white/5 overflow-y-auto no-scrollbar`}>
        <div className="p-6 mb-4">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-xl shadow-lg"><DhoolLogo className="w-8 h-8" /></div>
            {isSidebarOpen && <span className="text-xl font-black text-blue-500 tracking-tighter uppercase">DHOOL</span>}
          </div>
        </div>

        <nav className="flex-1 px-3">
          <NavItem id="dash" label={t('dashboard')} icon={LayoutDashboard} view="dashboard" />

          <NavGroup id="sales" label={t('sales')} icon={Receipt}>
            <NavItem id="pos-btn" label={t('pos')} view="pos" />
            <NavItem id="inv-btn" label={t('invoices')} view="invoices" />
          </NavGroup>

          <NavGroup id="clients" label={t('clients')} icon={Users}>
            <NavItem id="pat-list" label={t('patients')} view="patients" />
            <NavItem id="apt-list" label={t('appointments')} view="appointments" />
          </NavGroup>

          <NavGroup id="pharmacy-grp" label="Inventory" icon={Package}>
            <NavItem id="pharm-list" label={t('inventory')} view="pharmacy" />
          </NavGroup>

          <NavGroup id="finance-grp" label={t('finance')} icon={Wallet}>
            <NavItem id="exp-list" label={t('expenses')} view="expenses" />
            <NavItem id="tre-list" label={t('treasury')} view="treasury" />
            <NavItem id="sal-list" label="Payroll" view="salaries" />
          </NavGroup>

          <NavGroup id="reports-grp" label={t('reports')} icon={BarChart3}>
            <NavItem id="rep-all" label="All Reports" view="reports" />
          </NavGroup>

          <div className="mt-8 border-t border-white/5 pt-4">
            <NavItem id="usr-btn" label={t('admin')} icon={UserCircle} view="users" />
            <NavItem id="set-btn" label={t('settings')} icon={SettingsIcon} view="settings" />
          </div>
        </nav>

        <div className="p-4 mt-auto border-t border-white/5">
          <button onClick={syncWithDaftra} className="w-full flex items-center justify-center gap-3 p-3 rounded-xl bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white transition-all">
            <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
            {isSidebarOpen && <span className="text-[10px] font-black uppercase">Sync Daftra</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 z-10">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><Menu className="w-5 h-5" /></button>
            <div className="relative hidden md:block">
              {/* Added Search icon import from lucide-react */}
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
              <input placeholder="Search records..." className="bg-slate-50 border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-blue-500/20 w-64 transition-all" />
            </div>
          </div>

          <div className="flex items-center gap-6">
            {/* Added Bell icon import from lucide-react */}
            <div className="relative cursor-pointer"><Bell className="w-5 h-5 text-slate-400" /><span className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 text-white text-[8px] flex items-center justify-center rounded-full font-bold">3</span></div>
            <div className="h-8 w-px bg-slate-100"></div>
            <div className="flex items-center gap-3">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-slate-900">{currentUser.name}</p>
                <p className="text-[10px] font-bold text-blue-500 uppercase tracking-widest">{currentUser.role}</p>
              </div>
              <img src={currentUser.avatar} className="w-10 h-10 rounded-2xl bg-slate-100 p-1 border border-slate-200" />
            </div>
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-8 bg-[#f8fafc]">
          {activeView === 'dashboard' && <DashboardView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} />}
          {activeView === 'pos' && <POSView products={inventory} processSale={async (items, total, method, disc) => {
             const transactionId = `INV-${Date.now().toString().slice(-6)}`;
             const inv: Invoice = {
               id: transactionId,
               patientName: 'Walk-in Client',
               date: new Date().toLocaleDateString(),
               amount: total,
               discount: disc,
               totalPaid: total,
               status: 'Paid',
               type: 'Pharmacy',
               method: method
             };
             await supabaseService.insertInvoice(inv);
             await daftraApi.createInvoice({ amount: total, notes: `POS Sale #${transactionId} - Discount: ${disc}` });
             loadData();
          }} t={t} />}
          {activeView === 'patients' && <PatientsView patients={patients} addPatient={async p => { const res = await supabaseService.insertPatient(p); setPatients([res, ...patients]); }} patientHistory={patientHistory} addPatientHistory={async h => { await supabaseService.insertHistory(h); }} prescriptions={prescriptions} addPrescription={async pr => {}} user={currentUser} t={t} />}
          {activeView === 'appointments' && <AppointmentsView appointments={appointments} patients={patients} setAppointments={setAppointments} onAddAppointment={async a => { await supabaseService.insertAppointment(a); loadData(); }} />}
          {activeView === 'pharmacy' && <PharmacyView inventory={inventory} setInventory={setInventory} onAddMedicine={async m => { await supabaseService.insertMedicine(m); loadData(); }} />}
          {activeView === 'invoices' && <BillingView invoices={invoices} />}
          {activeView === 'expenses' && <ExpensesView expenses={expenses} setExpenses={setExpenses} />}
          {activeView === 'reports' && <ReportsView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} expenses={expenses} salaries={salaries} />}
          {activeView === 'users' && <UsersView appUsers={users} addUser={async u => ({success:true})} deleteUser={async id => {}} t={t} currentUser={currentUser} />}
          {activeView === 'settings' && <SettingsView user={currentUser} language={language} setLanguage={setLanguage} t={t} updateCurrentUser={async () => ({success:true})} />}
        </section>
      </main>
    </div>
  );
};

export default App;

