import React, { useState } from 'react';
import { ShoppingCart, ShoppingBag, Trash2, Package, Percent, Tag, DollarSign, Wallet, CreditCard } from 'lucide-react';
import { Medicine, CartItem, Product } from '../types';
import { Invoice as InvoiceReceipt } from '../components/Invoice';

interface Props {
  products: Product[];
  processSale: (items: { id: string; quantity: number }[], total: number, method: string, discount: number) => void;
  t: (key: string) => string;
}

const POSView: React.FC<Props> = ({ products, processSale, t }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [discount, setDiscount] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'percent' | 'flat'>('percent');
  const [showInvoice, setShowInvoice] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<{
    items: CartItem[];
    total: number;
    id: string;
    method: string;
    date: string;
    discount: number;
  } | null>(null);

  const addToCart = (product: Product) => {
    if (product.stock <= 0) return;
    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      if (existing.quantity >= product.stock) return;
      setCart(cart.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const calculateSubtotal = () => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const calculateTotal = () => {
    const sub = calculateSubtotal();
    if (discountType === 'percent') {
      return sub * (1 - discount / 100);
    }
    return Math.max(0, sub - discount);
  };

  const handleCheckout = (method: string) => {
    if (cart.length === 0) return;

    const finalTotal = calculateTotal();
    const transactionId = Math.floor(Math.random() * 900000 + 100000).toString();
    const date = new Date().toLocaleString();

    processSale(cart.map(i => ({ id: i.id, quantity: i.quantity })), finalTotal, method, discount);

    setLastTransaction({
      items: [...cart],
      total: finalTotal,
      id: transactionId,
      method,
      date,
      discount: discount
    });
    setShowInvoice(true);

    setCart([]);
    setDiscount(0);
  };

  return (
    <div className="h-full flex flex-col lg:flex-row bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden relative">

      {showInvoice && lastTransaction && (
        <InvoiceReceipt 
