          total={lastTransaction.total}
          transactionId={lastTransaction.id}
          date={lastTransaction.date}
          method={lastTransaction.method}
          onClose={() => setShowInvoice(false)}
          t={t}
        />
      )}

      {/* Product Area */}
      <div className="flex-1 flex flex-col min-w-0 bg-slate-50/30">
