          <div className="flex items-center gap-3 mb-4 px-2">
            <img src={currentUser.avatar} alt="Profile" className="w-10 h-10 rounded-full border border-gray-200 bg-white" />
            <div className="overflow-hidden">
              <p className="text-sm font-bold text-gray-900 truncate">{currentUser.name}</p>
              <p className="text-xs text-gray-500 truncate">{currentUser.role}</p>
            </div>
          </div>

          <button onClick={syncWithDaftra} className="w-full mb-3 flex items-center justify-center gap-2 p-2 rounded-xl bg-blue-600 text-white font-bold text-[10px] uppercase hover:bg-blue-700 transition-all">
            <RefreshCw className={`w-3 h-3 ${isSyncing ? 'animate-spin' : ''}`} />
            <span>Sync Daftra</span>
          </button>

          <button className="w-full flex items-center justify-center px-4 py-2 text-sm font-medium text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors">
            <LogOut className="mr-2 w-4 h-4" />
            {t('logout')}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 z-10">
          <div className="flex items-center gap-4">
            <div className="relative hidden md:block">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
              <input placeholder="Search records..." className="bg-slate-50 border-none rounded-xl pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-blue-500/20 w-64 transition-all" />
            </div>
          </div>
          <div className="flex items-center gap-6">
            <div className="relative cursor-pointer"><Bell className="w-5 h-5 text-slate-400" /><span className="absolute -top-1 -right-1 w-4 h-4 bg-rose-500 text-white text-[8px] flex items-center justify-center rounded-full font-bold">3</span></div>
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-8">
          {activeView === 'dashboard' && <DashboardView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} />}
          {activeView === 'pos' && <POSView products={inventory} processSale={async (items, total, method, disc) => {
             const transactionId = `INV-${Date.now().toString().slice(-6)}`;
             const inv: Invoice = {
               id: transactionId,
               patientName: 'Walk-in Client',
               date: new Date().toLocaleDateString(),
               amount: total,
               discount: disc,
               totalPaid: total,
               status: 'Paid',
               type: 'Pharmacy',
               method: method
             };
             await supabaseService.insertInvoice(inv);
