          {activeView === 'patients' && <PatientsView patients={patients} addPatient={async p => { await supabaseService.insertPatient(p); loadData(); }} patientHistory={[]} addPatientHistory={async h => { await supabaseService.insertHistory(h); }} prescriptions={[]} addPrescription={async pr => {}} user={currentUser} t={t} />}
          {activeView === 'appointments' && <AppointmentsView appointments={appointments} patients={patients} setAppointments={setAppointments} onAddAppointment={async a => { await supabaseService.insertAppointment(a); loadData(); }} />}
