          {activeView === 'users' && <UsersView appUsers={users} addUser={async u => { await supabaseService.insertUser(u); loadData(); return {success:true}; }} deleteUser={async id => {}} t={t} currentUser={currentUser} />}
          {activeView === 'settings' && <SettingsView user={currentUser} language={language} setLanguage={setLanguage} t={t} updateCurrentUser={async () => ({success:true})} />}
          {activeView === 'treasury' && (
