import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Users, Calendar, CreditCard, Menu, ChevronDown, ChevronRight,
  Package, Receipt, Wallet, UserCircle, BarChart3, ShoppingCart, RefreshCw, 
  Settings as SettingsIcon, LogOut, Landmark, PlusSquare, List,
  Search, Bell, Clock, Shield
} from 'lucide-react';
import { 
  ViewType, Patient, Appointment, Medicine, Invoice, 
  Expense, Salary, StaffUser, Role, PatientHistory, Prescription
} from './types';
import DashboardView from './views/DashboardView';
import PatientsView from './views/PatientsView';
import AppointmentsView from './views/AppointmentsView';
import PharmacyView from './views/PharmacyView';
import POSView from './views/POSView';
import BillingView from './views/BillingView';
import ExpensesView from './views/ExpensesView';
import SalariesView from './views/SalariesView';
import UsersView from './views/UsersView';
import ReportsView from './views/ReportsView';
import SettingsView from './views/SettingsView';
import { daftraApi } from './services/daftraService';
import { supabaseService } from './services/supabaseService';

export const DhoolLogo = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-10 h-10"} fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 15C38 15 28 22 25 35C22 55 35 70 45 85C47 88 50 92 50 95C50 92 53 88 55 85C65 70 78 55 75 35C72 22 62 15 50 15Z" stroke="url(#logoGrad)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M40 45C45 52 55 52 60 45" stroke="url(#logoGrad)" strokeWidth="4" strokeLinecap="round" opacity="0.6" />
    <defs>
      <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#0056b3" />
        <stop offset="100%" stopColor="#32cd32" />
      </linearGradient>
    </defs>
  </svg>
);

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  // Restore multiple groups array instead of single string
  const [expandedGroups, setExpandedGroups] = useState<string[]>(['pos_grp', 'sales', 'clients']);
  const [isSyncing, setIsSyncing] = useState(false);
  const [language, setLanguage] = useState<'so' | 'en'>('so');

  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([
    { id: '1', name: 'Admin User', role: 'Admin', email: 'admin@dhool.com', status: 'Active', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Admin' }
  ]);

  const currentUser = users[0];

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [p, m, a, i, e, s, u] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices(),
        supabaseService.getExpenses(),
        supabaseService.getSalaries(),
        supabaseService.getUsers()
      ]);
      setPatients(p || []);
      setInventory(m || []);
      setAppointments(a || []);
      setInvoices(i || []);
      setExpenses(e || []);
      setSalaries(s || []);
      if (u && u.length > 0) setUsers(u);
    } catch (error) {
      console.error("Data Load Error:", error);
    }
  };

  const syncWithDaftra = async () => {
    setIsSyncing(true);
    try {
      await daftraApi.getPatients();
      setIsSyncing(false);
      alert('Daftra Sync Success!');
    } catch (e: any) {
      setIsSyncing(false);
      alert('Daftra Sync Error: ' + e.message);
    }
  };

  const toggleGroup = (groupId: string) => {
    setExpandedGroups(prev => 
      prev.includes(groupId) ? prev.filter(g => g !== groupId) : [...prev, groupId]
    );
  };

  const t = (key: string) => {
    const dict: Record<string, any> = {
      so: {
        dashboard: 'Dashboard-ka',
        sales: 'Iibka',
        pos: 'Terminal-ka Iibka',
        invoices: 'Maamul Biilasha',
        clients: 'Bukaanada',
        patients: 'Liiska Bukaanada',
        finance: 'Maaliyadda',
        expenses: 'Kharashyada',
        reports: 'Warbixino',
        settings: 'Habsocodka',
        admin: 'Shaqaalaha',
        inventory: 'Dukumaatiga Dawooyinka',
        appointments: 'Ballamaha',
        logout: 'Kabax System-ka'
      },
      en: {
        dashboard: 'Dashboard',
        sales: 'Sales',
        pos: 'Point of Sale',
        invoices: 'Manage Invoices',
        clients: 'Clients',
        patients: 'Patients',
        finance: 'Finance',
        expenses: 'Expenses',
        reports: 'Reports',
        settings: 'Settings',
        admin: 'Personnel',
        inventory: 'Pharmacy Inventory',
        appointments: 'Appointments',
        logout: 'Logout'
      }
    };
    return dict[language]?.[key] || key;
  };

  const NavGroup = ({ id, label, icon: Icon, children }: { id: string, label: string, icon: any, children?: React.ReactNode }) => {
    const isExpanded = expandedGroups.includes(id);
    return (
      <div className="mb-1">
        <button 
          onClick={() => toggleGroup(id)}
          className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${isExpanded ? 'bg-white/5 text-blue-400' : 'text-slate-400 hover:text-white'}`}
        >
          <div className="flex items-center gap-3">
            <Icon className="w-5 h-5" />
            {isSidebarOpen && <span className="text-sm font-bold tracking-tight">{label}</span>}
          </div>
          {isSidebarOpen && (isExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />)}
        </button>
        {isExpanded && isSidebarOpen && (
          <div className="mt-1 ml-4 border-l border-white/5 pl-2 space-y-1 animate-in slide-in-from-left-2">
            {children}
          </div>
        )}
      </div>
    );
  };

  const NavItem = ({ label, view, icon: Icon, isNested = false }: { label: string, view: ViewType, icon?: any, isNested?: boolean }) => (
    <button
      onClick={() => setActiveView(view)}
      className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-xs font-bold transition-all ${
        activeView === view ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30' : 'text-slate-500 hover:text-white hover:bg-white/5'
      }`}
    >
      {Icon && <Icon className="w-4 h-4" />}
      {isSidebarOpen && <span>{label}</span>}
    </button>
  );

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900">
      {/* Dark Sidebar restored */}
      <aside className={`bg-[#111827] text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col border-r border-white/5 overflow-y-auto no-scrollbar shadow-2xl`}>
        <div className="p-6 mb-4">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-xl shadow-lg"><DhoolLogo className="w-8 h-8" /></div>
            {isSidebarOpen && <span className="text-xl font-black text-blue-500 tracking-tighter uppercase">DHOOL</span>}
          </div>
        </div>

        <nav className="flex-1 px-3">
          <div className="mb-4">
            <NavItem label={t('dashboard')} view="dashboard" icon={LayoutDashboard} />
          </div>

          <NavGroup id="pos_grp" label="POS" icon={ShoppingCart}>
             <NavItem label="Start Selling" view="pos" icon={ShoppingCart} />
             <NavItem label="POS Sessions" view="pos" icon={Clock} />
          </NavGroup>

          <NavGroup id="sales" label={t('sales')} icon={Receipt}>
            <NavItem label={t('invoices')} view="invoices" icon={Receipt} />
            <NavItem label="Create Invoice" view="invoices" icon={PlusSquare} />
          </NavGroup>

          <NavGroup id="clients" label={t('clients')} icon={Users}>
            <NavItem label={t('patients')} view="patients" icon={Users} />
