import { supabase } from '../lib/supabase';
import { Patient, Medicine, Appointment, Invoice, PatientHistory, Prescription, Expense, Salary, StaffUser } from '../types';

export const supabaseService = {
  // --- AUTH & USERS ---
  login: async (email: string) => {
    const { data, error } = await supabase
      .from('users')
      .select('*')
      .eq('email', email)
      .single();

    if (error) return null;
    return data as StaffUser;
  },

  getUsers: async () => {
    const { data, error } = await supabase.from('users').select('*').order('name');
    if (error) throw error;
    return data as StaffUser[];
  },

  insertUser: async (user: StaffUser) => {
    const { data, error } = await supabase.from('users').insert([user]).select();
    if (error) throw error;
    return data[0];
  },

  deleteUser: async (id: string) => {
    const { error } = await supabase.from('users').delete().eq('id', id);
    if (error) throw error;
  },

  updateUser: async (id: string, updates: Partial<StaffUser>) => {
    const { data, error } = await supabase.from('users').update(updates).eq('id', id).select();
    if (error) throw error;
    return data[0];
  },

  // --- PATIENTS ---
  getPatients: async () => {
    const { data, error } = await supabase.from('patients').select('*').order('name');
    if (error) throw error;
    return data as Patient[];
  },
  insertPatient: async (patient: Patient) => {
    const { data, error } = await supabase.from('patients').insert([patient]).select();
    if (error) throw error;
    return data[0];
  },

  // --- INVENTORY ---
  getInventory: async () => {
    const { data, error } = await supabase.from('inventory').select('*').order('name');
    if (error) throw error;
    return data as Medicine[];
  },
  insertMedicine: async (medicine: Medicine) => {
    const { data, error } = await supabase.from('inventory').insert([medicine]).select();
    if (error) throw error;
    return data[0];
  },

  // --- APPOINTMENTS ---
  getAppointments: async () => {
    const { data, error } = await supabase.from('appointments').select('*').order('date', { ascending: true });
    if (error) throw error;
    return data as Appointment[];
  },
  insertAppointment: async (appointment: Appointment) => {
    const { data, error } = await supabase.from('appointments').insert([appointment]).select();
    if (error) throw error;
    return data[0];
  },

  // --- BILLING ---
  getInvoices: async () => {
    const { data, error } = await supabase.from('invoices').select('*').order('date', { ascending: false });
    if (error) throw error;
    return data as Invoice[];
  },
  insertInvoice: async (invoice: Invoice) => {
    const { data, error } = await supabase.from('invoices').insert([invoice]).select();
    if (error) throw error;
    return data[0];
  },

  // --- EXPENSES ---
  getExpenses: async () => {
    const { data, error } = await supabase.from('expenses').select('*').order('date', { ascending: false });
    if (error) throw error;
    return data as Expense[];
  },
  insertExpense: async (expense: Expense) => {
    const { data, error } = await supabase.from('expenses').insert([expense]).select();
    if (error) throw error;
    return data[0];
  },

  // --- SALARIES ---
  getSalaries: async () => {
    const { data, error } = await supabase.from('salaries').select('*').order('date', { ascending: false });
    if (error) throw error;
    return data as Salary[];
  },
  insertSalary: async (salary: Salary) => {
    const { data, error } = await supabase.from('salaries').insert([salary]).select();
    if (error) throw error;
    return data[0];
  },

  // --- HISTORY ---
  insertHistory: async (history: PatientHistory) => {
    const { data, error } = await supabase.from('patient_history').insert([history]).select();
    if (error) throw error;
    return data[0];
  }
};

