  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [expandedGroup, setExpandedGroup] = useState<string | null>(null);
  const [language, setLanguage] = useState<'so' | 'en'>('so');

  const [currency, setCurrency] = useState('$');
  const [dateFormat, setDateFormat] = useState('DD/MM/YYYY');

  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('dhool_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    const savedLang = localStorage.getItem('dhool_lang');
    if (savedLang) setLanguage(savedLang as any);
  }, []);

  useEffect(() => {
    if (currentUser) loadData();
  }, [currentUser]);

  const loadData = async () => {
    try {
      const [p, m, a, i, e, s, u] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices(),
        supabaseService.getExpenses(),
        supabaseService.getSalaries(),
        supabaseService.getUsers()
      ]);
      setPatients(p || []);
      setInventory(m || []);
      setAppointments(a || []);
      setInvoices(i || []);
      setExpenses(e || []);
      setSalaries(s || []);
      setUsers(u || []);
    } catch (error) {
      console.error("Data Load Error:", error);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    try {
      // 1. Check direct fallback first for reliability
      if (email === 'admin@dhool.com' && pass === 'admin123') {
        const fallbackUser: StaffUser = { 
          id: '1', 
          name: 'Super Admin', 
          role: 'Admin', 
          email: 'admin@dhool.com', 
          status: 'Active', 
          avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Admin' 
        };
        setCurrentUser(fallbackUser);
        localStorage.setItem('dhool_user', JSON.stringify(fallbackUser));
        return true;
      }

      // 2. Try Supabase lookup
      const user = await supabaseService.login(email);
      if (user && user.password === pass) {
        setCurrentUser(user);
        localStorage.setItem('dhool_user', JSON.stringify(user));
        return true;
      }
    } catch (err) {
      console.error("Login attempt error:", err);
    }
    return false;
  };

