import React, { useState } from 'react';
import { StaffUser, Role } from '../types';
import { Shield, UserPlus, Trash2, Mail, Lock, User, X } from 'lucide-react';

interface Props {
  appUsers: StaffUser[];
  addUser: (user: StaffUser) => Promise<{ success: boolean; error?: string }>;
  deleteUser: (id: string) => Promise<void>;
  t: (key: string) => string;
  currentUser?: StaffUser;
}

export const UsersView: React.FC<Props> = ({ appUsers, addUser, deleteUser, t, currentUser }) => {
  const [showModal, setShowModal] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState<Role>('Staff');
  const [isLoading, setIsLoading] = useState(false);

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !email || !password) return;

    setIsLoading(true);
    const newUser: StaffUser = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      email,
      password,
      role,
      status: 'Active',
      avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${name.replace(/\s/g, '')}`
    };

    const result = await addUser(newUser);
    setIsLoading(false);

    if (result.success) {
        alert(t('userAdded'));
        setShowModal(false);
        setName(''); setEmail(''); setPassword(''); setRole('Staff');
    } else {
        alert(t('errorAddingUser') + (result.error ? `: ${result.error}` : ''));
    }
  };

  const handleDelete = async (id: string) => {
    if (id === currentUser?.id) {
      alert('You cannot delete yourself!');
      return;
    }
    if (window.confirm('Are you sure you want to delete this user?')) {
      await deleteUser(id);
    }
  };

  return (
    <div className="space-y-6 max-w-6xl mx-auto animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{t('admin')}</h1>
          <p className="text-slate-500 font-medium">Manage clinical staff and access permissions.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-blue-600 text-white px-6 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 hover:bg-blue-700 transition-all flex items-center gap-2"
        >
          <UserPlus className="w-4 h-4" />
          {t('addUser')}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {appUsers.map(u => (
          <div key={u.id} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4">
              <button 
                onClick={() => handleDelete(u.id)}
                disabled={u.id === currentUser?.id}
                className="p-2 text-slate-300 hover:text-rose-600 transition-colors disabled:opacity-0"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
            <div className="flex items-center gap-4 mb-6">
              <img src={u.avatar} className="w-16 h-16 rounded-2xl bg-slate-50 border border-slate-100 p-1" alt="" />
              <div>
                <h3 className="font-black text-slate-900 text-lg leading-tight">{u.name}</h3>
                <p className="text-xs font-bold text-slate-400 mt-0.5">{u.email}</p>
              </div>
            </div>
            <div className="flex items-center justify-between">
              <span className={`text-[10px] font-black uppercase tracking-widest px-4 py-1.5 rounded-full ${
                u.role === 'Admin' ? 'bg-purple-50 text-purple-600' : 
                u.role === 'Doctor' ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-500'
              }`}>
                {u.role}
              </span>
              <span className="flex items-center gap-1 text-[10px] font-bold text-emerald-500 uppercase tracking-widest">
                <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full"></div>
                {u.status}
              </span>
            </div>
          </div>
        ))}
      </div>

       {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-8 w-full max-w-md shadow-2xl relative overflow-hidden">
            <button onClick={() => setShowModal(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-900 transition-colors">
              <X className="w-5 h-5" />
            </button>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight mb-6">{t('addUser')}</h3>
            <form onSubmit={handleAddUser} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Staff Name</label>
                <div className="relative">
                  <input required value={name} onChange={e => setName(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none font-bold text-sm" placeholder="Full Name" />
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
                <div className="relative">
                  <input required type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none font-bold text-sm" placeholder="name@dhool.com" />
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">System Password</label>
                <div className="relative">
                  <input required type="password" value={password} onChange={e => setPassword(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none font-bold text-sm" placeholder="••••••••" />
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Assign Role</label>
                <select value={role} onChange={e => setRole(e.target.value as Role)} className="w-full p-4 bg-slate-50 rounded-2xl border border-transparent outline-none font-bold text-sm appearance-none cursor-pointer">
                  <option value="Admin">Admin</option>
                  <option value="Doctor">Doctor</option>
                  <option value="Staff">Staff</option>
                  <option value="Accountant">Accountant</option>
                </select>
              </div>

              <div className="flex gap-4 mt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-4 text-slate-500 font-black bg-slate-100 rounded-2xl hover:bg-slate-200 uppercase tracking-widest text-[10px]">Cancel</button>
                <button type="submit" disabled={isLoading} className="flex-1 py-4 text-white font-black bg-blue-600 rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-600/20 uppercase tracking-widest text-[10px]">
                    {isLoading ? 'Processing...' : 'Save User'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UsersView;

/**
 * Daftra API Service for Dhool Dental Clinic
 * API Key: jCfy6cMh1X6NTxR3OWLuvEFa0si5uZKr05UeoAEs
 */

const DAFTRA_API_KEY = 'jCfy6cMh1X6NTxR3OWLuvEFa0si5uZKr05UeoAEs';
const BASE_URL = 'https://dhool.daftra.com/api2'; 

export const daftraApi = {
  checkConnection: async () => {
    try {
      // Fetch just 1 client to test auth/connectivity without heavy load
      const response = await fetch(`${BASE_URL}/clients?limit=1`, {
        method: 'GET',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        }
      });
      return response.ok;
    } catch (error) {
      console.error('Daftra Connection Check Failed:', error);
      return false;
    }
  },

  getPatients: async () => {
    try {
      const response = await fetch(`${BASE_URL}/clients`, {
        method: 'GET',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        }
      });
      return await response.json();
    } catch (error) {
      console.error('Daftra Fetch Error:', error);
      return null;
    }
  },

  createClient: async (patient: { name: string; phone: string; email?: string }) => {
    try {
      const response = await fetch(`${BASE_URL}/clients`, {
        method: 'POST',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          Client: {
            first_name: patient.name,
            phone1: patient.phone,
            email: patient.email || ''
          }
        })
      });
      return await response.json();
    } catch (error) {
      console.error('Daftra Client Creation Error:', error);
      return null;
    }
  },

  createInvoice: async (invoiceData: { amount: number; notes: string; client_id?: number }) => {
    try {
      const response = await fetch(`${BASE_URL}/invoices`, {
        method: 'POST',
        headers: {
          'API-KEY': DAFTRA_API_KEY,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          Invoice: {
            client_id: invoiceData.client_id || 1, // Default to a generic client if not provided
            status: 1, // Draft or Paid based on settings
            invoice_items: [
              {
                item: "Clinical Service / Pharmacy",
                unit_price: invoiceData.amount,
                quantity: 1
              }
            ],
            notes: invoiceData.notes
          }
        })
      });
      return await response.json();
    } catch (error) {
      console.error('Daftra Invoice Error:', error);
      return null;
    }
  }
};

