);

export default App;

import React, { useState } from 'react';
import { User, Globe, Shield, Save, Camera, Lock, Calendar, DollarSign, Key, RefreshCw, CheckCircle2, AlertCircle } from 'lucide-react';
import { StaffUser } from '../types';

interface Props {
  user: StaffUser;
  language: 'so' | 'en';
  setLanguage: (lang: 'so' | 'en') => void;
  currency: string;
  setCurrency: (c: string) => void;
  dateFormat: string;
  setDateFormat: (f: string) => void;
  t: (key: string) => string;
  updateCurrentUser: (name: string, password?: string) => Promise<{ success: boolean; error?: string }>;
  daftraStatus: 'checking' | 'connected' | 'error';
  checkDaftraConnection: () => void;
}

const SettingsView: React.FC<Props> = ({ 
  user, language, setLanguage, currency, setCurrency, dateFormat, setDateFormat, t, updateCurrentUser,
  daftraStatus, checkDaftraConnection
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [name, setName] = useState(user?.name || '');
  const [password, setPassword] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    const result = await updateCurrentUser(name, password);
