        pos_grp: 'POS Terminal',
        pos_start: 'Start Selling',
        pharmacy: 'Pharmacy',
        sales_grp: 'Sales Management',
        invoices: 'Invoices',
        clients_grp: 'Clients',
        patients: 'Patients',
        finance_grp: 'Finance',
        expenses: 'Expenses',
        payroll: 'Payroll',
        reports: 'Reports',
        settings: 'Settings',
