    setActiveTab(mode === 'services' ? 'services' : 'inventory');
  }, [mode]);

  // Pre-defined services
  const clinicalServices = [
    { id: 'srv-1', name: 'Tooth Extraction', price: 30 },
    { id: 'srv-2', name: 'Root Canal', price: 150 },
    { id: 'srv-3', name: 'Teeth Cleaning', price: 40 },
    { id: 'srv-4', name: 'Filling (Composite)', price: 50 },
    { id: 'srv-5', name: 'Consultation Fee', price: 10 },
    { id: 'srv-6', name: 'X-Ray Imaging', price: 20 },
  ];

  const addToCart = (product: Product | { id: string, name: string, price: number, stock?: number, image?: string }) => {
    // If it's a product (has stock) check stock
    if (product.stock !== undefined && product.stock <= 0) return;

    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      if (product.stock !== undefined && existing.quantity >= product.stock) return;
      setCart(cart.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { 
        id: product.id, 
        name: product.name, 
        price: product.price, 
        stock: product.stock || 9999, 
        category: 'Service', 
        expiryDate: '',
        quantity: 1 
      }]);
    }
  };

  const addCustomService = () => {
    if (!customServiceName || !customServicePrice) return;
    const newService = {
      id: `custom-${Date.now()}`,
      name: customServiceName,
      price: parseFloat(customServicePrice),
      stock: 9999
