                 {mode === 'services' ? <Stethoscope className="w-5 h-5" /> : <Store className="w-5 h-5" />}
              </div>
              <div>
                <h2 className="text-xl font-black text-slate-900 tracking-tight">{mode === 'services' ? 'Clinical Services' : 'Pharmacy POS'}</h2>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{mode === 'services' ? 'Billing & Procedures' : 'Sales Terminal'}</p>
              </div>
           </div>

           {/* Hide tabs if strict mode is set, otherwise show them (legacy behavior if mode wasn't passed) */}
           {!mode && (
             <div className="flex bg-slate-100 p-1 rounded-xl">
               <button 
                 onClick={() => setActiveTab('services')}
