          {activeTab === 'inventory' && (
            <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
              {products.map(product => (
                <div key={product.id} onClick={() => addToCart(product)} className={`bg-white p-4 rounded-3xl border border-slate-200 cursor-pointer transition-all active:scale-95 flex flex-col group ${product.stock === 0 ? 'opacity-50 grayscale pointer-events-none' : 'hover:shadow-xl hover:border-blue-500 hover:-translate-y-1'}`}>
