import { supabase } from '../lib/supabase';
import { Patient, Medicine, Appointment, Invoice, PatientHistory, Prescription, Expense, Salary, StaffUser } from '../types';

// Local Storage Keys for Fallback
const KEYS = {
  USERS: 'dhool_local_users',
  PATIENTS: 'dhool_local_patients',
  INVENTORY: 'dhool_local_inventory',
  APPOINTMENTS: 'dhool_local_appointments',
  INVOICES: 'dhool_local_invoices',
  EXPENSES: 'dhool_local_expenses',
  SALARIES: 'dhool_local_salaries',
  HISTORY: 'dhool_local_history'
};

// Helper to handle Fallback Logic
const handleRequest = async <T>(
  supabasePromise: Promise<{ data: T | null; error: any }>, 
  localKey: string, 
  fallbackAction: 'get' | 'insert' | 'update' | 'delete',
  payload?: any
): Promise<T | any> => {
  try {
    const { data, error } = await supabasePromise;
    if (error) throw error;
    // Update local cache on successful Supabase fetch to keep them in sync
    if (fallbackAction === 'get' && data) {
       localStorage.setItem(localKey, JSON.stringify(data));
    }
    return data;
  } catch (error) {
    console.warn(`Supabase disconnected/failed for ${localKey}. Using Local Storage fallback.`);

    // Local Storage Logic
    let localData = JSON.parse(localStorage.getItem(localKey) || '[]');

    if (fallbackAction === 'get') {
      return localData;
    } 
    else if (fallbackAction === 'insert') {
      const newItem = Array.isArray(payload) ? payload[0] : payload;
      const updatedList = [...localData, newItem];
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return newItem;
    }
    else if (fallbackAction === 'update') {
      const updatedList = localData.map((item: any) => item.id === payload.id ? { ...item, ...payload.updates } : item);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return updatedList.find((i: any) => i.id === payload.id);
    }
    else if (fallbackAction === 'delete') {
      const updatedList = localData.filter((item: any) => item.id !== payload);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return null;
    }
  }
};

export const supabaseService = {
  // --- AUTH & USERS ---
  login: async (email: string) => {
    // Try Local First for immediate response or if offline
    const localUsers: StaffUser[] = JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
    const localUser = localUsers.find(u => u.email === email);
    if (localUser) return localUser;

    // Try Supabase
    try {
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .eq('email', email)
        .single();
      if (error) throw error;
      return data as StaffUser;
    } catch (e) {
      return null;
    }
  },

  getUsers: async () => {
    return handleRequest(
      supabase.from('users').select('*').order('name'),
      KEYS.USERS,
      'get'
    );
  },

  insertUser: async (user: StaffUser) => {
    return handleRequest(
      supabase.from('users').insert([user]).select(),
      KEYS.USERS,
      'insert',
      user
    );
  },

  deleteUser: async (id: string) => {
    return handleRequest(
      supabase.from('users').delete().eq('id', id),
      KEYS.USERS,
      'delete',
      id
    );
  },

  updateUser: async (id: string, updates: Partial<StaffUser>) => {
    // Supabase update is complex to mock return type exactly, so we simplify logic
    try {
       const { data, error } = await supabase.from('users').update(updates).eq('id', id).select();
       if (error) throw error;
       return data[0];
    } catch (e) {
       console.warn("Supabase update failed, using local");
       let localData = JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
       const updatedList = localData.map((item: any) => item.id === id ? { ...item, ...updates } : item);
       localStorage.setItem(KEYS.USERS, JSON.stringify(updatedList));
       return updatedList.find((i: any) => i.id === id);
    }
  },

  // --- PATIENTS ---
  getPatients: async () => {
    return handleRequest(
      supabase.from('patients').select('*').order('name'),
      KEYS.PATIENTS,
      'get'
    );
  },
  insertPatient: async (patient: Patient) => {
    return handleRequest(
      supabase.from('patients').insert([patient]).select(),
      KEYS.PATIENTS,
      'insert',
      patient
    );
  },

  // --- INVENTORY ---
  getInventory: async () => {
    return handleRequest(
      supabase.from('inventory').select('*').order('name'),
      KEYS.INVENTORY,
      'get'
    );
  },
  insertMedicine: async (medicine: Medicine) => {
    return handleRequest(
      supabase.from('inventory').insert([medicine]).select(),
      KEYS.INVENTORY,
      'insert',
      medicine
    );
  },

  // --- APPOINTMENTS ---
  getAppointments: async () => {
    return handleRequest(
      supabase.from('appointments').select('*').order('date', { ascending: true }),
      KEYS.APPOINTMENTS,
      'get'
    );
  },
  insertAppointment: async (appointment: Appointment) => {
    return handleRequest(
      supabase.from('appointments').insert([appointment]).select(),
      KEYS.APPOINTMENTS,
      'insert',
      appointment
