);

export default App;

export interface Patient {
  id: string;
  name: string;
  age: number;
  phone: string;
  email?: string;
  lastVisit: string;
  medicalHistory: string[];
  condition?: string;
  balance?: number;
}

export interface PatientHistory {
  id: string;
  patientId: string;
  date: string;
  diagnosis: string;
  treatment: string;
  notes: string;
  doctorName: string;
}

export interface Prescription {
  id: string;
  patientId: string;
  doctorName: string;
  date: string;
  medicines: {
    name: string;
    dosage: string;
    frequency: string;
    duration: string;
  }[];
}

export interface Appointment {
  id: string;
  patientId: string;
  patientName: string;
  doctor: string;
  date: string;
  time: string;
  status: 'Scheduled' | 'Completed' | 'Cancelled';
  reason: string;
}

export interface Medicine {
  id: string;
  name: string;
  stock: number;
  price: number;
  expiryDate: string;
  category: string;
  image?: string;
}

export interface Product extends Medicine {}

export interface CartItem extends Product {
  quantity: number;
}

export interface Invoice {
  id: string;
  patientName: string;
  date: string;
  amount: number;
  discount: number;
  totalPaid: number;
  status: 'Paid' | 'Pending' | 'Partial' | 'Refunded';
  type: 'Dental' | 'Pharmacy';
  method: string;
  isRefund?: boolean;
}

export interface Expense {
  id: string;
  description: string;
  category: 'Utilities' | 'Equipment' | 'Rent' | 'Procurement' | 'Salaries' | 'Other';
  amount: number;
  date: string;
}

export interface Salary {
  id: string;
  staffName: string;
  role: string;
  amount: number;
  month: string;
  date: string;
}

export type Role = 'Admin' | 'Doctor' | 'Staff' | 'Accountant';

export interface StaffUser {
  id: string;
  name: string;
  role: Role;
  email: string;
  status: 'Active' | 'Inactive';
  avatar?: string;
  password?: string;
}

export type ViewType = 
  | 'dashboard' 
  | 'patients' 
  | 'appointments' 
  | 'pharmacy' 
  | 'pos'
  | 'services'
  | 'invoices' 
  | 'expenses' 
  | 'salaries' 
  | 'users' 
  | 'reports'
  | 'treasury'
  | 'settings';

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Users, Calendar, CreditCard, Menu, ChevronDown, ChevronRight,
  Package, Receipt, Wallet, UserCircle, BarChart3, ShoppingCart, RefreshCw, 
  Settings as SettingsIcon, LogOut, Landmark, PlusSquare, List,
  Search, Bell, Clock, Shield, Stethoscope, Briefcase
} from 'lucide-react';
import { 
  ViewType, Patient, Appointment, Medicine, Invoice, 
  Expense, Salary, StaffUser, Role, PatientHistory, Prescription
} from './types';
import DashboardView from './views/DashboardView';
import PatientsView from './views/PatientsView';
import AppointmentsView from './views/AppointmentsView';
import PharmacyView from './views/PharmacyView';
import POSView from './views/POSView';
import BillingView from './views/BillingView';
import ExpensesView from './views/ExpensesView';
import SalariesView from './views/SalariesView';
import UsersView from './views/UsersView';
import ReportsView from './views/ReportsView';
import TreasuryView from './views/TreasuryView';
import SettingsView from './views/SettingsView';
import LoginView from './views/LoginView';
import { daftraApi } from './services/daftraService';
import { supabaseService } from './services/supabaseService';

export const DhoolLogo = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-10 h-10"} fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 15C38 15 28 22 25 35C22 55 35 70 45 85C47 88 50 92 50 95C50 92 53 88 55 85C65 70 78 55 75 35C72 22 62 15 50 15Z" stroke="url(#logoGrad)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M40 45C45 52 55 52 60 45" stroke="url(#logoGrad)" strokeWidth="4" strokeLinecap="round" opacity="0.6" />
    <defs>
      <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#0056b3" />
        <stop offset="100%" stopColor="#32cd32" />
      </linearGradient>
    </defs>
  </svg>
);

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<StaffUser | null>(null);
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [expandedGroup, setExpandedGroup] = useState<string | null>(null);
  const [language, setLanguage] = useState<'so' | 'en'>('en');

  const [currency, setCurrency] = useState('$');
  const [dateFormat, setDateFormat] = useState('DD/MM/YYYY');
  const [daftraStatus, setDaftraStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('dhool_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    const savedLang = localStorage.getItem('dhool_lang');
    if (savedLang) setLanguage(savedLang as any);

    // Check Daftra connection on load, but don't block
    checkDaftra();
  }, []);

  useEffect(() => {
    if (currentUser) loadData();
  }, [currentUser]);

  const checkDaftra = async () => {
    setDaftraStatus('checking');
    try {
      const isConnected = await daftraApi.checkConnection();
      setDaftraStatus(isConnected ? 'connected' : 'error');
    } catch (e) {
      setDaftraStatus('error');
    }
  };

  const loadData = async () => {
    try {
      const [p, m, a, i, e, s, u] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices(),
        supabaseService.getExpenses(),
        supabaseService.getSalaries(),
        supabaseService.getUsers()
      ]);
      setPatients(p || []);
      setInventory(m || []);
      setAppointments(a || []);
      setInvoices(i || []);
      setExpenses(e || []);
      setSalaries(s || []);
      setUsers(u || []);
    } catch (error) {
      console.error("Data Load Error:", error);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    if (email === 'admin@dhool.com' && pass === 'admin123') {
      const fallbackUser: StaffUser = { id: '1', name: 'Super Admin', role: 'Admin', email: 'admin@dhool.com', status: 'Active', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Admin' };
      setCurrentUser(fallbackUser);
      localStorage.setItem('dhool_user', JSON.stringify(fallbackUser));
      return true;
    }
    const user = await supabaseService.login(email);
    if (user && user.password === pass) {
      setCurrentUser(user);
      localStorage.setItem('dhool_user', JSON.stringify(user));
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('dhool_user');
    setActiveView('dashboard');
  };

  const t = (key: string) => {
    const dict: Record<string, any> = {
      so: {
        dashboard: 'Dashboard-ka',
        pos_grp: 'POS & Iibka',
        services: 'Adeegyada (Services)',
        pos_start: 'Iibka Farmashiga',
        pharmacy: 'Bakhaarka (Pharmacy)',
        sales_grp: 'Maamulka Iibka',
        invoices: 'Biilasha Dhameystiran',
        clients_grp: 'Bukaanada & Macmiisha',
        patients: 'Diiwaanka Bukaanada',
        finance_grp: 'Maaliyadda',
        expenses: 'Kharashyada',
        payroll: 'Mushaharka',
        treasury: 'Qasnadda (Treasury)',
        reports: 'Warbixinnada',
        settings: 'Settings',
        admin: 'User-ada',
        inventory: 'Pharmacy',
        appointments: 'Ballamaha',
        logout: 'Ka Bax',
        pos_sale_success: 'Iibka waa lagu guuleystay',
        userAdded: 'User-ka waa la kaydiyay!',
        errorAddingUser: 'Cillad ayaa dhacday markii la kaydinayay user-ka.'
      },
      en: {
        dashboard: 'Dashboard',
        pos_grp: 'POS & Sales',
        services: 'Clinical Services',
        pos_start: 'Pharmacy POS',
        pharmacy: 'Pharmacy Stock',
        sales_grp: 'Sales Management',
        invoices: 'Invoices',
        clients_grp: 'Clients',
        patients: 'Patients',
        finance_grp: 'Finance',
        expenses: 'Expenses',
        payroll: 'Payroll',
        treasury: 'Treasury & Accounts',
        reports: 'Reports',
        settings: 'Settings',
        admin: 'Users',
        inventory: 'Pharmacy',
        appointments: 'Appointments',
        logout: 'Logout',
        pos_sale_success: 'Sale Successful',
        userAdded: 'User saved successfully!',
        errorAddingUser: 'Error saving user.'
      }
    };
    return dict[language]?.[key] || key;
  };

  const canAccess = (view: ViewType) => {
    if (!currentUser) return false;
    if (currentUser.role === 'Admin') return true;
    switch(view) {
      case 'dashboard': return true;
      case 'patients': case 'appointments': case 'services': return ['Doctor', 'Staff', 'Admin'].includes(currentUser.role);
      case 'pos': case 'pharmacy': return ['Staff', 'Admin'].includes(currentUser.role);
      case 'invoices': case 'expenses': case 'salaries': case 'reports': case 'treasury': return ['Accountant', 'Admin'].includes(currentUser.role);
      case 'users': return currentUser.role === 'Admin';
      default: return true;
    }
  };

  const processStockDeduction = async (items: { id: string; quantity: number }[], isRefund: boolean) => {
    const updatedInventory = inventory.map(item => {
      const soldItem = items.find(i => i.id === item.id);
      if (soldItem) {
        // If refund, add stock back. If sale, subtract stock.
        const newStock = isRefund 
          ? item.stock + soldItem.quantity 
          : item.stock - soldItem.quantity;
        return { ...item, stock: Math.max(0, newStock) };
      }
      return item;
    });
    setInventory(updatedInventory);
    // Note: In a real app, you would batch update Supabase here
  };

  if (!currentUser) return <LoginView onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900">
      <aside className={`bg-[#111827] text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col border-r border-white/5 overflow-y-auto no-scrollbar shadow-2xl`}>
        <div className="p-6 mb-4">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-xl shadow-lg"><DhoolLogo className="w-8 h-8" /></div>
            {isSidebarOpen && <span className="text-xl font-black text-blue-500 tracking-tighter uppercase">DHOOL</span>}
          </div>
        </div>

        <nav className="flex-1 px-3">
          <NavItem 
            label={t('dashboard')} 
            active={activeView === 'dashboard'} 
            onClick={() => { setActiveView('dashboard'); setExpandedGroup(null); }} 
            icon={LayoutDashboard} 
          />

          <div className="h-4"></div>

          {canAccess('pos') && (
            <NavGroup id="pos" label={t('pos_grp')} isOpen={expandedGroup === 'pos'} onToggle={() => setExpandedGroup(expandedGroup === 'pos' ? null : 'pos')} isSidebarOpen={isSidebarOpen} icon={ShoppingCart}>
               <SubNavItem label={t('pos_start')} active={activeView === 'pos'} onClick={() => setActiveView('pos')} />
               <SubNavItem label={t('pharmacy')} active={activeView === 'pharmacy'} onClick={() => setActiveView('pharmacy')} />
            </NavGroup>
          )}

          {canAccess('services') && (
            <NavItem 
              label={t('services')} 
              active={activeView === 'services'} 
              onClick={() => { setActiveView('services'); setExpandedGroup(null); }} 
              icon={Stethoscope} 
            />
          )}

          {canAccess('invoices') && (
            <NavGroup id="sales" label={t('sales_grp')} isOpen={expandedGroup === 'sales'} onToggle={() => setExpandedGroup(expandedGroup === 'sales' ? null : 'sales')} isSidebarOpen={isSidebarOpen} icon={Receipt}>
              <SubNavItem label={t('invoices')} active={activeView === 'invoices'} onClick={() => setActiveView('invoices')} />
            </NavGroup>
          )}

          {canAccess('patients') && (
            <NavGroup id="clients" label={t('clients_grp')} isOpen={expandedGroup === 'clients'} onToggle={() => setExpandedGroup(expandedGroup === 'clients' ? null : 'clients')} isSidebarOpen={isSidebarOpen} icon={Users}>
              <SubNavItem label={t('patients')} active={activeView === 'patients'} onClick={() => setActiveView('patients')} />
            </NavGroup>
          )}

          {canAccess('expenses') && (
            <NavGroup id="finance" label={t('finance_grp')} isOpen={expandedGroup === 'finance'} onToggle={() => setExpandedGroup(expandedGroup === 'finance' ? null : 'finance')} isSidebarOpen={isSidebarOpen} icon={Wallet}>
              <SubNavItem label={t('treasury')} active={activeView === 'treasury'} onClick={() => setActiveView('treasury')} />
              <SubNavItem label={t('expenses')} active={activeView === 'expenses'} onClick={() => setActiveView('expenses')} />
              <SubNavItem label={t('payroll')} active={activeView === 'salaries'} onClick={() => setActiveView('salaries')} />
            </NavGroup>
          )}

          <div className="mt-8 border-t border-white/5 pt-4">
            {canAccess('appointments') && <NavItem label={t('appointments')} active={activeView === 'appointments'} onClick={() => { setActiveView('appointments'); setExpandedGroup(null); }} icon={Calendar} />}
            {canAccess('reports') && <NavItem label={t('reports')} active={activeView === 'reports'} onClick={() => { setActiveView('reports'); setExpandedGroup(null); }} icon={BarChart3} />}
            <NavItem label={t('settings')} active={activeView === 'settings'} onClick={() => { setActiveView('settings'); setExpandedGroup(null); }} icon={SettingsIcon} />
            {canAccess('users') && <NavItem label={t('admin')} active={activeView === 'users'} onClick={() => { setActiveView('users'); setExpandedGroup(null); }} icon={Shield} />}
          </div>
        </nav>

        <div className="p-4 mt-auto border-t border-white/5">
          <button onClick={handleLogout} className="w-full flex items-center justify-center px-4 py-2 text-sm font-medium text-rose-400 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
            <LogOut className="mr-2 w-4 h-4" /> 
            {isSidebarOpen && <span>{t('logout')}</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 z-10 shadow-sm">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><Menu className="w-5 h-5" /></button>
          </div>
          <div className="flex items-center gap-6">
            <div className="text-right hidden sm:block">
              <p className="text-xs font-black text-slate-900">{currentUser.name}</p>
              <p className="text-[10px] text-blue-500 font-bold uppercase tracking-widest">{currentUser.role}</p>
            </div>
            <img src={currentUser.avatar} className="w-10 h-10 rounded-2xl border border-slate-200 p-1 bg-slate-50" />
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-8 bg-[#f8fafc]">
          {activeView === 'dashboard' && <DashboardView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} />}

          {activeView === 'pos' && <POSView mode="pos" products={inventory} currency={currency} processSale={async (items, total, method, disc, isRefund) => {
             const transactionId = `INV-${Date.now().toString().slice(-6)}`;
             const finalAmount = isRefund ? -Math.abs(total) : total;
             const inv: Invoice = { 
               id: transactionId, 
               patientName: 'Pharmacy Client', 
               date: new Date().toISOString().split('T')[0], 
               amount: finalAmount, 
               discount: disc, 
               totalPaid: finalAmount, 
               status: isRefund ? 'Refunded' : 'Paid', 
               type: 'Pharmacy', 
               method: method,
               isRefund: isRefund 
             };
             try {
                // Update stock locally first for instant feedback
                await processStockDeduction(items, !!isRefund);
                await supabaseService.insertInvoice(inv);
                try { await daftraApi.createInvoice({ amount: finalAmount, notes: `POS ${isRefund ? 'Refund' : 'Sale'} #${transactionId}` }); } catch (daftraError) { console.warn("Daftra sync failed"); }
                loadData();
                return true;
             } catch (error) { console.error("Sale Error:", error); return false; }
          }} t={t} />}

          {activeView === 'services' && <POSView mode="services" products={[]} currency={currency} processSale={async (items, total, method, disc, isRefund) => {
             const transactionId = `SRV-${Date.now().toString().slice(-6)}`;
             const finalAmount = isRefund ? -Math.abs(total) : total;
             const inv: Invoice = { 
               id: transactionId, 
               patientName: 'Clinical Patient', 
               date: new Date().toISOString().split('T')[0], 
               amount: finalAmount, 
               discount: disc, 
               totalPaid: finalAmount, 
               status: isRefund ? 'Refunded' : 'Paid', 
               type: 'Dental', 
               method: method,
               isRefund: isRefund
             };
             try {
                await supabaseService.insertInvoice(inv);
                try { await daftraApi.createInvoice({ amount: finalAmount, notes: `Service ${isRefund ? 'Refund' : 'Bill'} #${transactionId}` }); } catch (daftraError) { console.warn("Daftra sync failed"); }
                loadData();
                return true;
             } catch (error) { console.error("Service Bill Error:", error); return false; }
          }} t={t} />}

          {activeView === 'patients' && <PatientsView patients={patients} addPatient={async p => { 
             try {
               await supabaseService.insertPatient(p); 
               try { await daftraApi.createClient({ name: p.name, phone: p.phone }); } catch (e) {}
               loadData(); 
             } catch(e) { console.error(e); }
          }} patientHistory={[]} addPatientHistory={async h => { await supabaseService.insertHistory(h); }} prescriptions={[]} addPrescription={async pr => {}} user={currentUser} t={t} />}
          {activeView === 'appointments' && <AppointmentsView appointments={appointments} patients={patients} setAppointments={setAppointments} onAddAppointment={async a => { await supabaseService.insertAppointment(a); loadData(); }} />}
          {activeView === 'pharmacy' && <PharmacyView inventory={inventory} setInventory={setInventory} onAddMedicine={async m => { await supabaseService.insertMedicine(m); loadData(); }} />}
          {activeView === 'invoices' && <BillingView invoices={invoices} />}
          {activeView === 'expenses' && <ExpensesView expenses={expenses} setExpenses={setExpenses} onAdd={async e => { await supabaseService.insertExpense(e); loadData(); }} />}
          {activeView === 'salaries' && <SalariesView salaries={salaries} setSalaries={setSalaries} />}
          {activeView === 'treasury' && <TreasuryView invoices={invoices} expenses={expenses} salaries={salaries} />}
          {activeView === 'reports' && <ReportsView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} expenses={expenses} salaries={salaries} />}
          {activeView === 'users' && <UsersView appUsers={users} addUser={async u => { 
              try { 
                const n = await supabaseService.insertUser(u); 
                loadData(); 
                return {success: !!n}; 
              } catch (e) { 
                return {success: false, error: 'Database Error'}; 
              } 
          }} deleteUser={async id => { await supabaseService.deleteUser(id); loadData(); }} t={t} currentUser={currentUser} />}
          {activeView === 'settings' && <SettingsView 
              user={currentUser} 
              language={language} 
              setLanguage={(l) => { setLanguage(l); localStorage.setItem('dhool_lang', l); }} 
              currency={currency} 
              setCurrency={setCurrency} 
              dateFormat={dateFormat} 
              setDateFormat={setDateFormat} 
              t={t} 
              updateCurrentUser={async (name, pass) => {
                const updated = await supabaseService.updateUser(currentUser.id, { name, ...(pass ? {password: pass} : {}) });
                if (updated) { setCurrentUser(updated); localStorage.setItem('dhool_user', JSON.stringify(updated)); return { success: true }; }
                return { success: false, error: 'Update Failed' };
              }}
              daftraStatus={daftraStatus}
              checkDaftraConnection={checkDaftra}
          />}
        </section>
      </main>
    </div>
  );
};

// Sidebar components with unified typography
const NavItem = ({ label, icon: Icon, active, onClick }: any) => (
  <button 
    onClick={onClick} 
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
      active ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30' : 'text-slate-400 hover:text-white hover:bg-white/5'
    }`}
  >
    <Icon className="w-5 h-5" /> 
    <span className="text-sm font-bold tracking-tight">{label}</span>
  </button>
);

const NavGroup = ({ label, icon: Icon, isOpen, onToggle, isSidebarOpen, children }: any) => (
  <div className="mb-1">
    <button 
      onClick={onToggle} 
      className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${
        isOpen ? 'bg-white/5 text-blue-400' : 'text-slate-400 hover:text-white'
      }`}
    >
      <div className="flex items-center gap-3">
        <Icon className="w-5 h-5" />
        {isSidebarOpen && <span className="text-sm font-bold tracking-tight">{label}</span>}
      </div>
      {isSidebarOpen && (isOpen ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />)}
    </button>
    {isOpen && isSidebarOpen && (
      <div className="mt-1 ml-4 border-l border-white/5 pl-2 space-y-1 animate-in slide-in-from-top-2">
        {children}
      </div>
    )}
  </div>
);

const SubNavItem = ({ label, active, onClick }: any) => (
  <button 
    onClick={onClick} 
    className={`w-full text-left px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
      active ? 'text-blue-500 bg-blue-500/10' : 'text-slate-500 hover:text-white hover:bg-white/5'
    }`}
  >
    {label}
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { ShoppingBag, Trash2, Package, Percent, DollarSign, Wallet, Stethoscope, Store, PenTool, RotateCcw } from 'lucide-react';
import { CartItem, Product } from '../types';
import { Invoice as InvoiceReceipt } from '../components/Invoice';

interface Props {
  products: Product[];
  currency: string;
  processSale: (items: { id: string; quantity: number }[], total: number, method: string, discount: number, isRefund: boolean) => Promise<boolean>;
  t: (key: string) => string;
  mode?: 'pos' | 'services';
}

const POSView: React.FC<Props> = ({ products, currency, processSale, t, mode = 'pos' }) => {
  const initialTab = mode === 'services' ? 'services' : 'inventory';
  const [activeTab, setActiveTab] = useState<'inventory' | 'services'>(initialTab);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [discount, setDiscount] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'percent' | 'flat'>('percent');
  const [showInvoice, setShowInvoice] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<any>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRefundMode, setIsRefundMode] = useState(false); // Refund Toggle

  const [customServiceName, setCustomServiceName] = useState('');
  const [customServicePrice, setCustomServicePrice] = useState('');

  useEffect(() => {
    setActiveTab(mode === 'services' ? 'services' : 'inventory');
  }, [mode]);

  const clinicalServices = [
    { id: 'srv-1', name: 'Tooth Extraction', price: 30 },
    { id: 'srv-2', name: 'Root Canal', price: 150 },
    { id: 'srv-3', name: 'Teeth Cleaning', price: 40 },
    { id: 'srv-4', name: 'Filling (Composite)', price: 50 },
    { id: 'srv-5', name: 'Consultation Fee', price: 10 },
    { id: 'srv-6', name: 'X-Ray Imaging', price: 20 },
  ];

  const addToCart = (product: Product | { id: string, name: string, price: number, stock?: number, image?: string }) => {
    // In Refund mode, we ignore stock limits because we are returning items
    if (!isRefundMode && product.stock !== undefined && product.stock <= 0) return;

    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      if (!isRefundMode && product.stock !== undefined && existing.quantity >= product.stock) return;
      setCart(cart.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item));
    } else {
      setCart([...cart, { 
        id: product.id, 
        name: product.name, 
        price: product.price, 
        stock: product.stock || 9999, 
        category: 'Service', 
        expiryDate: '',
        quantity: 1 
      }]);
    }
  };

  const addCustomService = () => {
    if (!customServiceName || !customServicePrice) return;
    const newService = {
      id: `custom-${Date.now()}`,
      name: customServiceName,
      price: parseFloat(customServicePrice),
      stock: 9999
    };
    addToCart(newService);
    setCustomServiceName('');
    setCustomServicePrice('');
  };

  const updateItemPrice = (id: string, newPrice: string) => {
    const val = parseFloat(newPrice);
    setCart(prev => prev.map(item => {
        if (item.id === id) {
            return { ...item, price: isNaN(val) ? 0 : val };
        }
        return item;
    }));
  };

  const calculateSubtotal = () => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const calculateTotal = () => {
    const sub = calculateSubtotal();
    return discountType === 'percent' ? sub * (1 - discount / 100) : Math.max(0, sub - discount);
  };

  const handleCheckout = async (method: string) => {
    if (isProcessing) return;
    setIsProcessing(true);

    const finalTotal = calculateTotal();
    const transactionId = Math.floor(Math.random() * 900000 + 100000).toString();

    try {
      // Pass isRefundMode to the processSale function
      await processSale(cart.map(i => ({ id: i.id, quantity: i.quantity })), finalTotal, method, discount, isRefundMode);

      setLastTransaction({ 
        items: [...cart], 
        total: isRefundMode ? -finalAmount : finalTotal, 
        id: transactionId, 
        method, 
        date: new Date().toLocaleString(), 
        discount,
        isRefund: isRefundMode
      });
      setShowInvoice(true);
      setCart([]); 
      setDiscount(0);
      setIsRefundMode(false); // Reset mode after transaction
    } catch (e) {
      alert("Error processing sale. Please check connection.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className={`h-full flex flex-col lg:flex-row bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden relative transition-colors ${isRefundMode ? 'border-rose-300' : ''}`}>
      {showInvoice && lastTransaction && <InvoiceReceipt {...lastTransaction} onClose={() => setShowInvoice(false)} t={t} />}

      <div className={`flex-1 flex flex-col min-w-0 ${isRefundMode ? 'bg-rose-50/50' : 'bg-slate-50/30'}`}>
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white">
           <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-white shadow-lg ${isRefundMode ? 'bg-rose-600' : (mode === 'services' ? 'bg-emerald-600' : 'bg-blue-600')}`}>
                 {isRefundMode ? <RotateCcw className="w-5 h-5" /> : (mode === 'services' ? <Stethoscope className="w-5 h-5" /> : <Store className="w-5 h-5" />)}
              </div>
              <div>
                <h2 className="text-xl font-black text-slate-900 tracking-tight">
                    {isRefundMode ? 'Refund Terminal' : (mode === 'services' ? 'Clinical Services' : 'Pharmacy POS')}
                </h2>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                    {isRefundMode ? 'Return Items to Stock' : 'Sales Terminal'}
                </p>
              </div>
           </div>

           <div className="flex items-center gap-2">
             <button 
               onClick={() => setIsRefundMode(!isRefundMode)}
               className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all flex items-center gap-2 ${isRefundMode ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-rose-600 border-rose-200 hover:bg-rose-50'}`}
             >
               <RotateCcw className="w-3 h-3" /> Refund Mode
             </button>

             {!mode && (
               <div className="flex bg-slate-100 p-1 rounded-xl">
                 <button 
                   onClick={() => setActiveTab('services')}
                   className={`px-4 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'services' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
                 >
                   Services
                 </button>
                 <button 
                   onClick={() => setActiveTab('inventory')}
                   className={`px-4 py-2 rounded-lg text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'inventory' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}
                 >
                   Pharmacy
                 </button>
               </div>
             )}
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 no-scrollbar">
          {activeTab === 'services' && (
            <div className="space-y-6">
              <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm">
                <div className="flex items-center gap-2 mb-4">
                  <PenTool className="w-4 h-4 text-emerald-500" />
                  <h3 className="font-black text-slate-900 text-sm uppercase tracking-wider">Custom Procedure Entry</h3>
                </div>
                <div className="flex gap-4">
                  <input 
                    value={customServiceName} 
                    onChange={e => setCustomServiceName(e.target.value)}
                    placeholder="e.g. Tooth Brushing, Special Cleaning..." 
                    className="flex-1 px-4 py-3 bg-slate-50 rounded-xl border-none outline-none font-bold text-sm focus:ring-2 focus:ring-emerald-100"
                  />
                  <div className="relative w-32">
                    <span className="absolute left-3 top-1/2 -translate-y-1/2 font-bold text-slate-400">{currency}</span>
                    <input 
                      type="number"
                      value={customServicePrice} 
                      onChange={e => setCustomServicePrice(e.target.value)}
                      placeholder="0.00" 
                      className="w-full pl-8 pr-4 py-3 bg-slate-50 rounded-xl border-none outline-none font-bold text-sm focus:ring-2 focus:ring-emerald-100"
                    />
                  </div>
                  <button 
                    onClick={addCustomService}
                    disabled={!customServiceName || !customServicePrice}
                    className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-emerald-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Add
                  </button>
                </div>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
                {clinicalServices.map(srv => (
                   <div key={srv.id} onClick={() => addToCart(srv)} className="bg-white p-5 rounded-3xl border border-slate-200 cursor-pointer transition-all hover:shadow-lg hover:border-emerald-500 active:scale-95 group">
                      <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center mb-3 group-hover:bg-emerald-600 group-hover:text-white transition-colors">
                        <Stethoscope className="w-5 h-5" />
                      </div>
                      <h3 className="font-black text-slate-800 text-sm mb-1 leading-tight">{srv.name}</h3>
                      <p className="text-emerald-600 font-black">{currency}{srv.price}</p>
                   </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'inventory' && (
            <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
              {products.map(product => (
                <div key={product.id} onClick={() => addToCart(product)} className={`bg-white p-4 rounded-3xl border border-slate-200 cursor-pointer transition-all active:scale-95 flex flex-col group ${!isRefundMode && product.stock === 0 ? 'opacity-50 grayscale pointer-events-none' : 'hover:shadow-xl hover:border-blue-500 hover:-translate-y-1'}`}>
                  <div className="h-24 bg-slate-50 rounded-2xl mb-4 flex items-center justify-center text-slate-300 relative overflow-hidden group-hover:bg-blue-50">
                    {product.image ? <img src={product.image} className="w-full h-full object-cover" alt={product.name} /> : <Package className="w-8 h-8 group-hover:scale-125 transition-transform" />}
                  </div>
                  <h3 className="font-black text-slate-800 text-xs mb-1 truncate">{product.name}</h3>
                  <div className="flex justify-between items-end mt-auto">
                    <span className="text-blue-600 font-black text-lg">{currency}{product.price.toFixed(2)}</span>
                    <span className={`text-[10px] font-bold uppercase tracking-widest ${product.stock < 5 ? 'text-rose-500' : 'text-slate-400'}`}>{product.stock} left</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      <div className="w-full lg:w-[400px] bg-white border-l border-slate-100 flex flex-col">
        <div className={`p-6 border-b border-slate-100 flex items-center justify-between ${isRefundMode ? 'bg-rose-50' : 'bg-slate-50/50'}`}>
           <h3 className={`text-sm font-black uppercase tracking-widest ${isRefundMode ? 'text-rose-900' : 'text-slate-900'}`}>
               {isRefundMode ? 'Refund Items' : 'Billing Summary'}
           </h3>
           <div className={`${isRefundMode ? 'bg-rose-600' : 'bg-blue-600'} text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black`}>{cart.length}</div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 no-scrollbar">
          {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-20 text-center">
               <ShoppingBag className="w-24 h-24 mb-4 stroke-1" />
               <p className="font-black uppercase tracking-widest text-[10px]">Your basket is empty</p>
             </div>
          ) : (
            cart.map((item, idx) => (
              <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 hover:bg-white hover:shadow-md transition-all group">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center font-black text-blue-600 border border-slate-200 shadow-sm">x{item.quantity}</div>
                    <div>
                       <p className="font-black text-slate-900 text-xs truncate w-32 mb-1">{item.name}</p>
                       <div className="flex items-center bg-white rounded-lg border border-slate-200 px-2 py-1 w-24 focus-within:border-blue-500 focus-within:ring-2 focus-within:ring-blue-500/20 transition-all">
                            <span className="text-[10px] font-bold text-slate-400 mr-1">{currency}</span>
                            <input 
                                type="number" 
                                value={item.price} 
                                onChange={(e) => updateItemPrice(item.id, e.target.value)}
                                className="w-full bg-transparent border-none outline-none text-xs font-black text-blue-600 p-0"
                                onFocus={(e) => e.target.select()}
                            />
                       </div>
                    </div>
                 </div>
                 <button onClick={() => setCart(cart.filter(c => c.id !== item.id))} className="p-2 text-slate-300 hover:text-rose-600 transition-colors bg-transparent hover:bg-rose-50 rounded-lg"><Trash2 className="w-4 h-4" /></button>
              </div>
            ))
          )}
        </div>

        <div className={`p-8 border-t border-slate-200 space-y-6 ${isRefundMode ? 'bg-rose-50' : 'bg-slate-50'}`}>
          {!isRefundMode && (
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                  <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">Discount</span>
                  <div className="flex bg-white rounded-lg p-1 border border-slate-200">
                    <button onClick={() => setDiscountType('percent')} className={`px-3 py-1 rounded-md text-[10px] font-black ${discountType === 'percent' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400'}`}>%</button>
                    <button onClick={() => setDiscountType('flat')} className={`px-3 py-1 rounded-md text-[10px] font-black ${discountType === 'flat' ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400'}`}>{currency}</button>
                  </div>
              </div>
              <input type="number" value={discount || ''} onChange={(e) => setDiscount(parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-black outline-none focus:border-blue-500" placeholder="0.00" />
            </div>
          )}

          <div className="space-y-2 border-t border-slate-200 pt-6">
             <div className="flex justify-between items-center">
                <span className={`text-sm font-black uppercase tracking-widest ${isRefundMode ? 'text-rose-900' : 'text-slate-900'}`}>{isRefundMode ? 'Refund Total' : 'Total to Pay'}</span>
                <span className={`text-3xl font-black ${isRefundMode ? 'text-rose-600' : 'text-blue-700'}`}>
                    {isRefundMode ? '-' : ''}{currency}{calculateTotal().toFixed(2)}
                </span>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-3 pt-4">
             <button onClick={() => handleCheckout('Cash')} disabled={cart.length === 0 || isProcessing} className="py-4 bg-white border-2 border-slate-200 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:border-blue-600 transition-all flex flex-col items-center justify-center gap-1 shadow-sm disabled:opacity-50">
                <DollarSign className="w-4 h-4" /> <span>{isProcessing ? 'Processing...' : (isRefundMode ? 'Refund Cash' : 'Cash')}</span>
             </button>
             <button onClick={() => handleCheckout('EVC-Plus')} disabled={cart.length === 0 || isProcessing} className={`py-4 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl transition-all flex flex-col items-center justify-center gap-1 disabled:opacity-50 ${isRefundMode ? 'bg-rose-600 hover:bg-rose-700' : 'bg-blue-600 hover:bg-blue-700'}`}>
                <Wallet className="w-4 h-4" /> <span>{isProcessing ? 'Processing...' : (isRefundMode ? 'Refund Mobile' : 'Mobile Money')}</span>
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

