           <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-125 transition-transform duration-500">
             <TrendingUp className="w-32 h-32" />
           </div>
           <p className="text-emerald-100 font-black uppercase tracking-[0.2em] text-[10px] mb-2">Net Cash Gain (Profit)</p>
           <h3 className="text-4xl font-black tracking-tighter">${netProfit.toLocaleString(undefined, { minimumFractionDigits: 2 })}</h3>
           <div className="mt-6 flex items-center gap-2 text-[10px] font-bold bg-white/10 w-fit px-3 py-1.5 rounded-full backdrop-blur-md">
             <Calendar className="w-3 h-3 text-emerald-300" />
