import React, { useState, useEffect } from 'react';
import { ShoppingBag, Trash2, Package, Percent, DollarSign, Wallet, Stethoscope, Store, PenTool, RotateCcw, Plus } from 'lucide-react';
import { CartItem, Product, ClinicalService } from '../types';
import { InvoiceReceipt } from '../components/InvoiceReceipt';
import { Invoice } from '../components/Invoice';

interface Props {
  products: Product[];
  services: ClinicalService[];
  currency: string;
  processSale: (items: { id: string; quantity: number }[], total: number, method: string, discount: number, isRefund: boolean) => Promise<boolean>;
  onAddService: (service: ClinicalService) => Promise<void>;
  t: (key: string) => string;
  mode?: 'pos' | 'services';
}

const POSView: React.FC<Props> = ({ products, services, currency, processSale, onAddService, t, mode = 'pos' }) => {
  const initialTab = mode === 'services' ? 'services' : 'inventory';
  const [activeTab, setActiveTab] = useState<'inventory' | 'services'>(initialTab);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [discount, setDiscount] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'percent' | 'flat'>('percent');
  const [showReceipt, setShowReceipt] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<any>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRefundMode, setIsRefundMode] = useState(false); 

  // New Service Form
  const [showAddService, setShowAddService] = useState(false);
  const [newServiceName, setNewServiceName] = useState('');
  const [newServicePrice, setNewServicePrice] = useState('');
  const [newServiceCat, setNewServiceCat] = useState('General');

  useEffect(() => {
    setActiveTab(mode === 'services' ? 'services' : 'inventory');
  }, [mode]);

  const handleAddNewService = async () => {
    if (!newServiceName || !newServicePrice) return;
    const srv: ClinicalService = {
        id: `srv-${Date.now()}`,
        name: newServiceName,
        price: parseFloat(newServicePrice),
        category: newServiceCat
    };
    await onAddService(srv);
    setNewServiceName(''); setNewServicePrice(''); setShowAddService(false);
  };

  const addToCart = (item: Product | ClinicalService) => {
    const isService = mode === 'services';
    const product = item as Product;

    // Check Stock only for Pharmacy Mode
    if (!isService && !isRefundMode && product.stock !== undefined && product.stock <= 0) return;

    const existing = cart.find(i => i.id === item.id);
    if (existing) {
      if (!isService && !isRefundMode && product.stock !== undefined && existing.quantity >= product.stock) return;
      setCart(cart.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i));
    } else {
      setCart([...cart, { 
        id: item.id, 
        name: item.name, 
        price: item.price, 
        stock: (item as Product).stock || 9999, 
        category: (item as Product).category || 'Service', 
        expiryDate: (item as Product).expiryDate || '',
        quantity: 1 
      }]);
    }
  };

  const updateItemPrice = (id: string, newPrice: string) => {
    const val = parseFloat(newPrice);
    setCart(prev => prev.map(item => {
        if (item.id === id) {
            return { ...item, price: isNaN(val) ? 0 : val };
        }
        return item;
    }));
  };

  const calculateSubtotal = () => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const calculateTotal = () => {
    const sub = calculateSubtotal();
    return discountType === 'percent' ? sub * (1 - discount / 100) : Math.max(0, sub - discount);
  };

  const handleCheckout = async (method: string) => {
    if (isProcessing) return;
    setIsProcessing(true);

    const finalTotal = calculateTotal();
    const transactionId = Math.floor(Math.random() * 900000 + 100000).toString();

    try {
      await processSale(cart.map(i => ({ id: i.id, quantity: i.quantity })), finalTotal, method, discount, isRefundMode);

      setLastTransaction({ 
        items: [...cart], 
        total: isRefundMode ? -finalTotal : finalTotal, 
        transactionId: transactionId, 
        id: transactionId,
        patientName: mode === 'services' ? 'Clinical Patient' : 'Pharmacy Client',
        method, 
        date: new Date().toISOString().split('T')[0], 
        discount,
        isRefund: isRefundMode
      });
      setShowReceipt(true);
      setCart([]); 
      setDiscount(0);
      setIsRefundMode(false);
    } catch (e) {
      alert("Error processing sale. Please check connection.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className={`h-full flex flex-col lg:flex-row bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden relative transition-colors ${isRefundMode ? 'border-rose-300' : ''}`}>
      {/* Smart Invoice Rendering: Services -> A4 Invoice, POS -> Thermal Receipt */}
      {showReceipt && lastTransaction && mode === 'pos' && <InvoiceReceipt {...lastTransaction} onClose={() => setShowReceipt(false)} />}
      {showReceipt && lastTransaction && mode === 'services' && <Invoice {...lastTransaction} onClose={() => setShowReceipt(false)} t={t} />}

      <div className={`flex-1 flex flex-col min-w-0 ${isRefundMode ? 'bg-rose-50/50' : 'bg-slate-50/30'}`}>
        <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white">
           <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-white shadow-lg ${isRefundMode ? 'bg-rose-600' : (mode === 'services' ? 'bg-emerald-600' : 'bg-blue-600')}`}>
                 {isRefundMode ? <RotateCcw className="w-5 h-5" /> : (mode === 'services' ? <Stethoscope className="w-5 h-5" /> : <Store className="w-5 h-5" />)}
              </div>
              <div>
                <h2 className="text-xl font-black text-slate-900 tracking-tight">
                    {isRefundMode ? 'Refund Terminal' : (mode === 'services' ? 'Clinical Billing' : 'Pharmacy POS')}
                </h2>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">
                    {isRefundMode ? 'Return Items to Stock' : (mode === 'services' ? 'Procedures & Services' : 'Sales Terminal')}
                </p>
              </div>
           </div>

           <div className="flex items-center gap-2">
             <button 
               onClick={() => setIsRefundMode(!isRefundMode)}
               className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all flex items-center gap-2 ${isRefundMode ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-rose-600 border-rose-200 hover:bg-rose-50'}`}
             >
               <RotateCcw className="w-3 h-3" /> Refund Mode
             </button>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 no-scrollbar">
          {activeTab === 'services' && (
            <div className="space-y-6">
              {/* Dynamic Service Adder */}
              <div className="flex justify-between items-center">
                  <h3 className="font-black text-slate-400 text-xs uppercase tracking-widest ml-1">Available Procedures</h3>
                  <button onClick={() => setShowAddService(!showAddService)} className="text-blue-600 text-[10px] font-black uppercase tracking-widest hover:underline flex items-center gap-1">
                      <Plus className="w-3 h-3" /> Add Service
                  </button>
              </div>

              {showAddService && (
                <div className="bg-white p-4 rounded-2xl border border-blue-100 shadow-sm flex gap-2 animate-in fade-in slide-in-from-top-2">
                    <input placeholder="Service Name" value={newServiceName} onChange={e=>setNewServiceName(e.target.value)} className="flex-1 px-3 py-2 bg-slate-50 rounded-xl text-xs font-bold outline-none" />
                    <input type="number" placeholder="Price" value={newServicePrice} onChange={e=>setNewServicePrice(e.target.value)} className="w-24 px-3 py-2 bg-slate-50 rounded-xl text-xs font-bold outline-none" />
                    <button onClick={handleAddNewService} className="bg-blue-600 text-white px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest">Save</button>
                </div>
              )}

              <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-4">
                {services.map(srv => (
                   <div key={srv.id} onClick={() => addToCart(srv)} className="bg-white p-5 rounded-3xl border border-slate-200 cursor-pointer transition-all hover:shadow-lg hover:border-emerald-500 active:scale-95 group">
                      <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center mb-3 group-hover:bg-emerald-600 group-hover:text-white transition-colors">
                        <Stethoscope className="w-5 h-5" />
                      </div>
                      <h3 className="font-black text-slate-800 text-sm mb-1 leading-tight">{srv.name}</h3>
                      <p className="text-emerald-600 font-black">{currency}{srv.price}</p>
                   </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'inventory' && (
