} from 'lucide-react';
import { Patient, PatientHistory, Prescription, StaffUser } from '../types';

interface Props {
  patients: Patient[];
  addPatient: (p: Patient) => void;
  patientHistory: PatientHistory[];
  addPatientHistory: (h: PatientHistory) => Promise<void>;
  prescriptions: Prescription[];
  addPrescription: (pr: Prescription) => Promise<void>;
  user: StaffUser;
  t: (key: string) => string;
}

const PatientsView: React.FC<Props> = ({ 
  patients, addPatient, patientHistory, addPatientHistory, 
  prescriptions, addPrescription, user, t 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  // New Patient Form
  const [name, setName] = useState('');
  const [age, setAge] = useState('');
  const [phone, setPhone] = useState('');
  const [condition, setCondition] = useState('');

  // History Form
  const [diagnosis, setDiagnosis] = useState('');
  const [treatment, setTreatment] = useState('');
  const [notes, setNotes] = useState('');
  const [historyDoctorName, setHistoryDoctorName] = useState(user?.name || '');

  // Prescription Form
  const [medName, setMedName] = useState('');
  const [medDosage, setMedDosage] = useState('');
  const [medFrequency, setMedFrequency] = useState('');
  const [medDuration, setMedDuration] = useState('');
  const [currentMeds, setCurrentMeds] = useState<{name:string, dosage:string, frequency:string, duration:string}[]>([]);

  // Tabs in Detail View
  const [detailTab, setDetailTab] = useState<'info' | 'history' | 'prescription'>('info');

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault(); // Stop page refresh
    if (isSaving) return;
    setIsSaving(true);

    try {
        const newPatient: Patient = {
          id: Math.random().toString(36).substr(2, 9),
          name,
          age: parseInt(age),
          phone,
          lastVisit: new Date().toISOString().split('T')[0],
          medicalHistory: [],
          condition: condition || 'Checkup'
        };

        await addPatient(newPatient);

        // Clear and Close
        setShowAddModal(false);
        setName(''); setAge(''); setPhone(''); setCondition('');
    } catch(err) {
        console.error(err);
        alert('Could not save patient. Please check your connection.');
    } finally {
        setIsSaving(false);
    }
  };

  const handleAddHistory = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPatient) return;
    const newHistory: PatientHistory = {
      id: Date.now().toString(),
      patientId: selectedPatient.id,
      date: new Date().toISOString().split('T')[0],
      diagnosis,
      treatment,
      notes,
      doctorName: historyDoctorName || user?.name || 'Doctor'
    };
    await addPatientHistory(newHistory);
    setDiagnosis(''); setTreatment(''); setNotes('');
    // Reset doctor name to user name for next time or keep it
  };

  const addMedToPrescription = () => {
    if (!medName) return;
    setCurrentMeds([...currentMeds, { name: medName, dosage: medDosage, frequency: medFrequency, duration: medDuration }]);
    setMedName(''); setMedDosage(''); setMedFrequency(''); setMedDuration('');
  };

  const handleSavePrescription = async () => {
    if (!selectedPatient || currentMeds.length === 0) return;
    const newRx: Prescription = {
      id: Date.now().toString(),
      patientId: selectedPatient.id,
      doctorName: user?.name || 'Doctor',
      date: new Date().toISOString().split('T')[0],
      medicines: currentMeds
    };
    await addPrescription(newRx);
    setCurrentMeds([]);
  };

  const printPrescription = (rx: Prescription) => {
    const printWindow = window.open('', '', 'height=800,width=800');
    if (!printWindow) return;

    const patient = patients.find(p => p.id === rx.patientId);

    printWindow.document.write('<html><head><title>Prescription - Dhool Dental</title>');
    printWindow.document.write('<style>');
    printWindow.document.write(`
      @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;900&display=swap');
      body { font-family: 'Inter', sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; -webkit-print-color-adjust: exact; }
      .container { max-width: 700px; margin: 0 auto; border: 1px solid #eee; padding: 40px; }
      .header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 40px; border-bottom: 4px solid #0f172a; padding-bottom: 20px; }
      .brand h1 { font-size: 32px; font-weight: 900; margin: 0; color: #0f172a; letter-spacing: -1px; }
      .brand p { margin: 0; font-size: 11px; font-weight: 700; color: #3b82f6; text-transform: uppercase; letter-spacing: 2px; }
      .meta { text-align: right; font-size: 12px; color: #64748b; }

      .patient-card { background: #f8fafc; padding: 24px; border-radius: 12px; display: flex; justify-content: space-between; margin-bottom: 40px; border: 1px solid #e2e8f0; }
      .patient-info h3 { margin: 0 0 4px 0; font-size: 18px; font-weight: 800; color: #0f172a; }
      .patient-info p { margin: 0; font-size: 13px; color: #64748b; }

      .rx-symbol { font-family: serif; font-size: 64px; font-weight: bold; font-style: italic; color: #0f172a; margin-bottom: 20px; line-height: 1; }

      .med-table { width: 100%; border-collapse: collapse; margin-bottom: 60px; }
      .med-table th { text-align: left; padding: 12px 0; border-bottom: 2px solid #e2e8f0; font-size: 10px; text-transform: uppercase; letter-spacing: 1px; color: #94a3b8; font-weight: 800; }
      .med-table td { padding: 16px 0; border-bottom: 1px solid #f1f5f9; vertical-align: top; }
      .med-name { font-weight: 700; color: #0f172a; font-size: 14px; display: block; margin-bottom: 2px; }
      .med-detail { font-size: 13px; color: #475569; }

      .footer { margin-top: 60px; border-top: 1px solid #e2e8f0; padding-top: 30px; display: flex; justify-content: space-between; align-items: flex-end; }
      .doc-sig { text-align: center; }
      .doc-line { width: 200px; border-bottom: 1px solid #0f172a; margin-bottom: 8px; }
      .doc-name { font-size: 12px; font-weight: 700; color: #0f172a; text-transform: uppercase; }
      .disclaimer { font-size: 10px; color: #94a3b8; max-width: 300px; }
    `);
    printWindow.document.write('</style></head><body>');

    printWindow.document.write(`
      <div class="container">
        <div class="header">
          <div class="brand">
            <h1>DHOOL</h1>
            <p>Dental Clinic</p>
          </div>
          <div class="meta">
            <div>Maka Al-Mukarama Rd, Mogadishu</div>
            <div>+252 61 5000000</div>
            <div>Generated: ${rx.date}</div>
          </div>
        </div>

        <div class="patient-card">
          <div class="patient-info">
             <div style="font-size: 10px; text-transform: uppercase; color: #94a3b8; font-weight: 700; margin-bottom: 4px;">Patient Details</div>
             <h3>${patient?.name}</h3>
             <p>Age: ${patient?.age} • Phone: ${patient?.phone}</p>
          </div>
          <div class="patient-info" style="text-align: right;">
             <div style="font-size: 10px; text-transform: uppercase; color: #94a3b8; font-weight: 700; margin-bottom: 4px;">Attending Physician</div>
             <h3 style="color: #3b82f6;">Dr. ${rx.doctorName}</h3>
             <p>ID: #${rx.id.slice(-6)}</p>
          </div>
        </div>

        <div class="rx-symbol">Rx</div>

        <table class="med-table">
          <thead>
            <tr>
              <th width="40%">Medication</th>
              <th width="20%">Dosage</th>
              <th width="20%">Frequency</th>
              <th width="20%">Duration</th>
            </tr>
          </thead>
          <tbody>
            ${rx.medicines.map(m => `
              <tr>
                <td><span class="med-name">${m.name}</span></td>
                <td class="med-detail">${m.dosage}</td>
                <td class="med-detail">${m.frequency}</td>
                <td class="med-detail">${m.duration}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>

        <div class="footer">
          <div class="disclaimer">
            This document is a valid medical prescription issued by Dhool Dental Clinic. 
            Please dispense as written.
          </div>
          <div class="doc-sig">
            <div class="doc-line"></div>
            <div class="doc-name">Doctor's Signature</div>
          </div>
        </div>
      </div>
    `);

    printWindow.document.write('</body></html>');
    printWindow.document.close();
    setTimeout(() => {
        printWindow.print();
    }, 500);
  };

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.phone.includes(searchTerm)
  );

  return (
    <div className="space-y-6 max-w-7xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">{t('patients')} Registry</h1>
          <p className="text-slate-500 font-medium">Manage clinical records and prescriptions.</p>
        </div>
        <button 
           onClick={() => setShowAddModal(true)}
           className="bg-blue-600 text-white px-6 py-3 rounded-2xl text-sm font-black shadow-xl shadow-blue-600/20 hover:bg-blue-700 transition-all flex items-center gap-2 uppercase tracking-wider"
        >
          <Plus className="w-4 h-4" />
          Register Patient
        </button>
      </div>

      <div className="relative max-w-md">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
        <input 
          type="text" 
          placeholder="Search by name or phone..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl shadow-sm outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all font-medium text-sm"
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredPatients.map(patient => (
          <div key={patient.id} onClick={() => setSelectedPatient(patient)} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl hover:border-blue-200 transition-all cursor-pointer group relative overflow-hidden">
             <div className="absolute top-0 right-0 p-6 opacity-0 group-hover:opacity-100 transition-opacity">
               <ChevronRight className="w-5 h-5 text-blue-500" />
             </div>
             <div className="flex items-center gap-4 mb-6">
               <div className="w-14 h-14 bg-gradient-to-br from-blue-500 to-blue-700 rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-500/30 group-hover:scale-110 transition-transform">
                 {patient.name.charAt(0)}
               </div>
               <div>
                 <h3 className="font-black text-slate-900 text-lg tracking-tight group-hover:text-blue-600 transition-colors">{patient.name}</h3>
                 <div className="flex items-center gap-1.5 text-slate-400 text-xs font-bold">
                   <Phone className="w-3 h-3" /> {patient.phone}
                 </div>
               </div>
             </div>
             <div className="grid grid-cols-2 gap-3">
                <div className="bg-slate-50 rounded-2xl p-3 border border-slate-100">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Age</span>
                  <span className="font-black text-slate-900">{patient.age} Yrs</span>
                </div>
                <div className="bg-blue-50/50 rounded-2xl p-3 border border-blue-50">
                  <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest block mb-1">Condition</span>
                  <span className="font-black text-blue-600 truncate block">{patient.condition}</span>
                </div>
             </div>
             <div className="mt-4 flex items-center justify-between px-1">
                <span className="text-[10px] font-bold text-slate-400 flex items-center gap-1">
                  <Calendar className="w-3 h-3" /> Last Visit: {patient.lastVisit}
                </span>
             </div>
          </div>
        ))}
      </div>

      {filteredPatients.length === 0 && (
          <div className="flex flex-col items-center justify-center py-24 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
             <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center text-slate-300 mb-6">
               <Users className="w-10 h-10" />
             </div>
             <h3 className="text-xl font-black text-slate-900 tracking-tight">Empty Registry</h3>
             <p className="text-slate-400 font-medium mb-6">No patients matching your search were found.</p>
             <button onClick={() => setShowAddModal(true)} className="text-blue-600 font-black hover:underline uppercase tracking-widest text-xs">Add New Patient Entry</button>
          </div>
      )}

      {/* Add Patient Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-8 w-full max-md shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-6">
              <button onClick={() => setShowAddModal(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="mb-8">
              <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mb-4">
                <Users className="w-6 h-6" />
              </div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Registration</h3>
              <p className="text-sm text-slate-500 font-medium">Create a new file in the clinic database</p>
            </div>

            <form onSubmit={handleAddPatient} className="space-y-5">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Identity</label>
                <input required value={name} onChange={e => setName(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="e.g. Ahmed Farah" />
              </div>

              <div className="flex gap-4">
                <div className="w-1/3 space-y-1.5">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Age</label>
                   <input required type="number" value={age} onChange={e => setAge(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="25" />
                </div>
                <div className="flex-1 space-y-1.5">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Phone</label>
                   <input required value={phone} onChange={e => setPhone(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="063-XXXXXX" />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Initial Condition</label>
                <input value={condition} onChange={e => setCondition(e.target.value)} placeholder="e.g. Toothache" className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" />
              </div>

              <div className="pt-4">
                <button type="submit" disabled={isSaving} className="w-full py-5 text-white font-black bg-blue-600 rounded-2xl hover:bg-blue-700 shadow-2xl shadow-blue-600/30 transition-all uppercase tracking-widest text-xs disabled:opacity-50">
                  {isSaving ? 'Saving...' : 'Complete Registration'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Patient Details Modal */}
      {selectedPatient && (
         <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
           <div className="bg-white rounded-[3rem] w-full max-w-5xl h-[90vh] shadow-2xl overflow-hidden flex flex-col relative">

              {/* Detailed Header */}
              <div className="bg-slate-900 text-white p-8 flex justify-between items-start relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600 rounded-full blur-[100px] opacity-20 -mr-32 -mt-32"></div>
                 <div className="relative z-10">
                    <div className="flex items-center gap-6">
                      <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center text-white font-black text-3xl shadow-xl shadow-blue-600/40">
                        {selectedPatient.name.charAt(0)}
                      </div>
                      <div>
                        <h2 className="text-4xl font-black tracking-tight">{selectedPatient.name}</h2>
                        <p className="text-slate-400 font-bold mt-1 text-sm flex items-center gap-3">
                          <span className="flex items-center gap-1.5"><Activity className="w-4 h-4 text-emerald-400" /> {selectedPatient.age} Yrs</span>
                          <span className="w-1 h-1 bg-slate-700 rounded-full"></span>
                          <span className="flex items-center gap-1.5"><Phone className="w-4 h-4 text-blue-400" /> {selectedPatient.phone}</span>
                        </p>
                      </div>
                    </div>
                 </div>
                 <button onClick={() => setSelectedPatient(null)} className="relative z-10 text-white bg-white/10 p-3 rounded-2xl hover:bg-white/20 transition-all backdrop-blur-md border border-white/5">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              {/* Advanced Navigation */}
              <div className="flex bg-slate-50 px-8 border-b border-slate-200">
                 {[
                   { id: 'info', label: 'File Information', icon: FileText },
                   { id: 'history', label: 'Diagnosis & Logs', icon: Stethoscope },
                   { id: 'prescription', label: 'E-Prescriptions', icon: Activity }
                 ].map(tab => (
                   <button 
                    key={tab.id}
                    onClick={() => setDetailTab(tab.id as any)} 
                    className={`flex items-center gap-2.5 px-6 py-5 font-black text-xs uppercase tracking-widest transition-all relative ${
                      detailTab === tab.id ? 'text-blue-600' : 'text-slate-400 hover:text-slate-600'
                    }`}
                   >
                    <tab.icon className="w-4 h-4" />
                    {tab.label}
                    {detailTab === tab.id && <div className="absolute bottom-0 left-0 w-full h-1 bg-blue-600 rounded-full"></div>}
                   </button>
                 ))}
              </div>

              {/* Dynamic Content Area */}
              <div className="flex-1 overflow-y-auto p-8 bg-slate-50/50">

                 {detailTab === 'info' && (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in fade-in slide-in-from-bottom-2">
                       <div className="lg:col-span-2 space-y-6">
                          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                             <h3 className="text-lg font-black text-slate-900 mb-6 flex items-center gap-2">
                               <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                               Demographics & Metadata
                             </h3>
                             <div className="grid grid-cols-2 md:grid-cols-2 gap-8">
                                <DataPoint label="Patient Full Name" value={selectedPatient.name} />
                                <DataPoint label="Registered Contact" value={selectedPatient.phone} />
                                <DataPoint label="Age Bracket" value={`${selectedPatient.age} Years`} />
                                <DataPoint label="Last Clinical Visit" value={selectedPatient.lastVisit} />
                                <DataPoint label="Preferred Email" value={selectedPatient.email || 'Not Provided'} />
                                <DataPoint label="File Reference ID" value={`#${selectedPatient.id}`} />
                             </div>
                          </div>
                       </div>

                       <div className="space-y-6">
                          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                             <h3 className="text-lg font-black text-slate-900 mb-6">Health Tags</h3>
                             <div className="flex flex-wrap gap-2">
                                {selectedPatient.medicalHistory.length > 0 ? selectedPatient.medicalHistory.map((tag, idx) => (
                                  <span key={idx} className="bg-slate-100 text-slate-600 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider">{tag}</span>
                                )) : <p className="text-slate-400 text-sm font-medium italic">No tags assigned yet.</p>}
                             </div>
                          </div>
                       </div>
                    </div>
                 )}

                 {detailTab === 'history' && (
                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in slide-in-from-bottom-2">
                       {/* Add New History Form */}
                       <div className="lg:col-span-4 h-fit sticky top-0">
                          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                            <h3 className="text-xl font-black text-slate-900 mb-6">New Diagnosis</h3>
                            <form onSubmit={handleAddHistory} className="space-y-5">
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Clinical Diagnosis</label>
                                  <input required value={diagnosis} onChange={e => setDiagnosis(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="e.g. Impacted Wisdom Tooth" />
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Treatment Performed</label>
                                  <textarea required value={treatment} onChange={e => setTreatment(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm h-28 resize-none" placeholder="Description of procedure..." />
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observation Notes</label>
                                  <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm h-24 resize-none" placeholder="Extra findings..." />
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Doctor's Name</label>
                                  <input required value={historyDoctorName} onChange={e => setHistoryDoctorName(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="Dr. Ahmed" />
                               </div>
                               <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-600/20 transition-all uppercase tracking-widest text-[10px]">Log Diagnosis</button>
                            </form>
                          </div>
                       </div>

                       {/* History List */}
                       <div className="lg:col-span-8 space-y-6">
                          <h3 className="text-xl font-black text-slate-900 px-4">Historical Timeline</h3>
                          <div className="space-y-4">
                            {patientHistory.filter(h => h.patientId === selectedPatient.id).length === 0 ? (
                               <div className="bg-white p-12 rounded-[2.5rem] text-center border border-dashed border-slate-200">
                                  <p className="text-slate-400 font-bold">No clinical history recorded for this patient yet.</p>
                               </div>
                            ) : (
                               patientHistory.filter(h => h.patientId === selectedPatient.id).reverse().map(history => (
                                  <div key={history.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex gap-6 relative group overflow-hidden">
                                     <div className="absolute left-0 top-0 h-full w-2 bg-blue-600"></div>
                                     <div className="flex-1">
