        services: 'Clinical Services',
        pos_start: 'Pharmacy POS',
        pharmacy: 'Pharmacy Stock',
        sales_grp: 'Sales Management',
        invoices: 'Invoices',
        clients_grp: 'Clients',
        patients: 'Patients',
        finance_grp: 'Finance',
        expenses: 'Expenses',
        payroll: 'Payroll',
