          {activeView === 'pos' && <POSView 
            mode="pos" 
            products={inventory} 
            services={[]} 
            currency={currency} 
            processSale={async (items, total, method, disc, isRefund) => {
             const transactionId = `INV-${Date.now().toString().slice(-6)}`;
             const finalAmount = isRefund ? -Math.abs(total) : total;
             const inv: Invoice = { 
               id: transactionId, 
               patientName: 'Pharmacy Client', 
               date: new Date().toISOString().split('T')[0], 
               amount: finalAmount, 
               discount: disc, 
               totalPaid: finalAmount, 
               status: isRefund ? 'Refunded' : 'Paid', 
               type: 'Pharmacy', 
               method: method,
               isRefund: isRefund 
             };
             try {
                await processStockDeduction(items, !!isRefund);
                await supabaseService.insertInvoice(inv);
                loadData();
                return true;
             } catch (error) { console.error("Sale Error:", error); return false; }
          }} t={t} onAddService={async ()=>{}} />}

          {activeView === 'services' && <POSView 
