                       </div>

                       <div className="space-y-6">
                          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                             <h3 className="text-lg font-black text-slate-900 mb-6">Health Tags</h3>
                             <div className="flex flex-wrap gap-2">
                                {selectedPatient.medicalHistory.length > 0 ? selectedPatient.medicalHistory.map((tag, idx) => (
                                  <span key={idx} className="bg-slate-100 text-slate-600 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-wider">{tag}</span>
                                )) : <p className="text-slate-400 text-sm font-medium italic">No tags assigned yet.</p>}
                             </div>
                          </div>
                       </div>
                    </div>
                 )}

                 {detailTab === 'history' && (
                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in slide-in-from-bottom-2">
                       {/* Add New History Form */}
                       <div className="lg:col-span-4 h-fit sticky top-0">
                          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                            <h3 className="text-xl font-black text-slate-900 mb-6">New Diagnosis</h3>
                            <form onSubmit={handleAddHistory} className="space-y-5">
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Clinical Diagnosis</label>
                                  <input required value={diagnosis} onChange={e => setDiagnosis(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="e.g. Impacted Wisdom Tooth" />
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Treatment Performed</label>
                                  <textarea required value={treatment} onChange={e => setTreatment(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm h-28 resize-none" placeholder="Description of procedure..." />
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Observation Notes</label>
                                  <textarea value={notes} onChange={e => setNotes(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm h-24 resize-none" placeholder="Extra findings..." />
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Doctor's Name</label>
                                  <input required value={historyDoctorName} onChange={e => setHistoryDoctorName(e.target.value)} className="w-full px-5 py-4 bg-slate-50 rounded-2xl border border-transparent focus:bg-white focus:border-blue-500 outline-none transition-all font-bold text-sm" placeholder="Dr. Ahmed" />
                               </div>
                               <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl hover:bg-blue-700 shadow-xl shadow-blue-600/20 transition-all uppercase tracking-widest text-[10px]">Log Diagnosis</button>
                            </form>
                          </div>
                       </div>

                       {/* History Timeline */}
                       <div className="lg:col-span-8 space-y-6">
                          <div className="flex justify-between items-center px-4">
                             <h3 className="text-xl font-black text-slate-900">Medical Timeline</h3>
                             <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest bg-slate-100 px-3 py-1 rounded-full">
                                {patientHistory.filter(h => h.patientId === selectedPatient.id).length} Records
                             </span>
                          </div>

                          <div className="relative pl-8 border-l-2 border-slate-200 ml-4 space-y-8 py-2">
                            {patientHistory.filter(h => h.patientId === selectedPatient.id).length === 0 ? (
                               <div className="bg-white p-12 rounded-[2.5rem] text-center border border-dashed border-slate-200 -ml-8">
                                  <p className="text-slate-400 font-bold">No clinical history recorded for this patient yet.</p>
                               </div>
                            ) : (
                               patientHistory.filter(h => h.patientId === selectedPatient.id).reverse().map((history, idx) => (
                                  <div key={history.id} className="relative">
                                     {/* Timeline Dot */}
                                     <div className="absolute -left-[41px] top-6 w-5 h-5 bg-blue-600 rounded-full border-4 border-slate-50 shadow-sm z-10"></div>

                                     <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 group hover:shadow-md transition-all">
                                        <div className="flex justify-between items-start mb-4">
                                           <div>
                                             <div className="flex items-center gap-3 mb-1">
                                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1">
                                                   <Clock className="w-3 h-3" /> {history.date}
                                                </span>
                                             </div>
                                             <h4 className="font-black text-slate-900 text-lg">{history.diagnosis}</h4>
                                           </div>
                                           <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-xl uppercase tracking-widest border border-blue-100">
                                              Dr. {history.doctorName}
                                           </span>
                                        </div>

                                        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 mb-4">
                                           <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-1">Treatment Plan</span>
                                           <p className="text-sm text-slate-700 font-medium leading-relaxed">{history.treatment}</p>
                                        </div>

                                        {history.notes && (
                                            <div className="flex gap-2 items-start">
                                                <FileText className="w-4 h-4 text-slate-400 mt-0.5" />
                                                <p className="text-xs text-slate-500 italic font-medium">"{history.notes}"</p>
                                            </div>
                                        )}
                                     </div>
                                  </div>
                               ))
                            )}
                          </div>
                       </div>
                    </div>
                 )}

                 {/* PRESCRIPTION TAB */}
                 {detailTab === 'prescription' && (
                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in slide-in-from-bottom-2">
                       {/* Create New Rx */}
                       <div className="lg:col-span-5 h-fit sticky top-0">
                          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
                             <div className="flex items-center gap-3 mb-6">
                                <div className="w-10 h-10 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center">
                                  <Activity className="w-5 h-5" />
                                </div>
                                <h3 className="text-xl font-black text-slate-900">Prescription Builder</h3>
                             </div>

                             <div className="space-y-4 mb-6">
                                <div className="space-y-1.5 relative">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Medication Name</label>
                                  <div className="relative">
                                      <input 
                                        placeholder="e.g. Ibuprofen" 
                                        value={medName} 
                                        onChange={e => {
                                            setMedName(e.target.value);
                                            setShowSuggestions(true);
                                        }}
                                        onFocus={() => setShowSuggestions(true)}
                                        onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                                        className="w-full px-4 py-3 bg-slate-50 rounded-2xl border border-transparent font-bold text-sm outline-none focus:bg-white focus:border-emerald-500" 
                                      />
                                      {/* Autocomplete Dropdown */}
                                      {showSuggestions && medName && (
                                          <div className="absolute top-full left-0 w-full bg-white border border-slate-100 rounded-2xl shadow-xl mt-2 z-50 max-h-48 overflow-y-auto no-scrollbar p-2 animate-in fade-in slide-in-from-top-2">
                                              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2 py-1 mb-1">Pharmacy Stock</div>
                                              {inventory.filter(m => m.name.toLowerCase().includes(medName.toLowerCase())).map(m => (
                                                  <button 
                                                    key={m.id} 
                                                    type="button"
                                                    onClick={() => {
                                                        setMedName(m.name);
                                                        setShowSuggestions(false);
                                                    }}
                                                    className="w-full text-left p-3 hover:bg-emerald-50 rounded-xl cursor-pointer flex justify-between items-center group transition-colors"
                                                  >
                                                      <span className="font-bold text-slate-700 text-sm group-hover:text-emerald-700">{m.name}</span>
                                                      <span className="text-[10px] font-bold text-slate-400 bg-slate-100 px-2 py-1 rounded-lg group-hover:bg-emerald-100 group-hover:text-emerald-600 flex items-center gap-1">
                                                        <Package className="w-3 h-3" /> {m.stock}
                                                      </span>
                                                  </button>
                                              ))}
                                              {inventory.filter(m => m.name.toLowerCase().includes(medName.toLowerCase())).length === 0 && (
                                                  <div className="p-3 text-center text-xs font-bold text-slate-400 italic">No matches in stock. <br/> Custom entry allowed.</div>
                                              )}
                                          </div>
                                      )}
                                  </div>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                  <div className="space-y-1.5">
                                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dosage</label>
                                    <input placeholder="400mg" value={medDosage} onChange={e => setMedDosage(e.target.value)} className="w-full px-4 py-3 bg-slate-50 rounded-2xl border border-transparent font-bold text-sm outline-none focus:bg-white focus:border-emerald-500" />
                                  </div>
                                  <div className="space-y-1.5">
                                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Frequency</label>
                                    <input placeholder="3x Daily" value={medFrequency} onChange={e => setMedFrequency(e.target.value)} className="w-full px-4 py-3 bg-slate-50 rounded-2xl border border-transparent font-bold text-sm outline-none focus:bg-white focus:border-emerald-500" />
                                  </div>
                                </div>
                                <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Duration</label>
                                  <input placeholder="7 Days" value={medDuration} onChange={e => setMedDuration(e.target.value)} className="w-full px-4 py-3 bg-slate-50 rounded-2xl border border-transparent font-bold text-sm outline-none focus:bg-white focus:border-emerald-500" />
                                </div>
                             </div>

                             <button onClick={addMedToPrescription} type="button" className="w-full py-4 bg-slate-100 text-slate-700 font-black rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-[10px] mb-6 border border-slate-200">Stage Medication</button>

                             {currentMeds.length > 0 && (
                                <div className="mb-6 space-y-3">
                                   <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest ml-1">Staged Medications ({currentMeds.length})</span>
                                   <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100 divide-y divide-emerald-200/50">
                                      {currentMeds.map((m, i) => (
                                         <div key={i} className="py-2 first:pt-0 last:pb-0 flex justify-between items-center">
                                            <div>
                                              <p className="font-black text-emerald-900 text-sm">{m.name}</p>
                                              <p className="text-[10px] font-bold text-emerald-600 opacity-70">{m.dosage} • {m.frequency} • {m.duration}</p>
                                            </div>
                                            <button onClick={() => setCurrentMeds(prev => prev.filter((_, idx) => idx !== i))} className="text-emerald-300 hover:text-rose-500">
                                              <X className="w-4 h-4" />
                                            </button>
                                         </div>
                                      ))}
                                   </div>
                                </div>
                             )}

                             <button onClick={handleSavePrescription} disabled={currentMeds.length === 0} className="w-full py-5 bg-emerald-600 text-white font-black rounded-2xl hover:bg-emerald-700 shadow-xl shadow-emerald-600/20 disabled:opacity-50 transition-all uppercase tracking-widest text-[10px]">Generate & Finalize Rx</button>
                          </div>
                       </div>

                       {/* List of Previous Prescriptions */}
                       <div className="lg:col-span-7 space-y-6">
                          <h3 className="text-xl font-black text-slate-900 px-4">Electronic Logs</h3>
                          <div className="space-y-4">
                            {prescriptions.filter(p => p.patientId === selectedPatient.id).length === 0 ? (
                               <div className="bg-white p-12 rounded-[2.5rem] text-center border border-dashed border-slate-200">
                                  <p className="text-slate-400 font-bold">No pharmaceutical history found.</p>
                               </div>
                            ) : (
                               prescriptions.filter(p => p.patientId === selectedPatient.id).reverse().map(rx => (
                                  <div key={rx.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex justify-between items-center group hover:border-emerald-200 transition-all">
                                     <div className="flex items-center gap-5">
                                        <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-2xl flex items-center justify-center font-black">
                                          Rx
                                        </div>
                                        <div>
                                           <p className="font-black text-slate-900 text-lg">{rx.date}</p>
                                           <div className="flex items-center gap-2 text-xs font-bold text-slate-400 mt-0.5">
                                              <Activity className="w-3 h-3" /> {rx.medicines.length} Items • <Users className="w-3 h-3" /> Dr. {rx.doctorName}
                                           </div>
                                        </div>
                                     </div>
                                     <button onClick={() => printPrescription(rx)} className="px-6 py-3 bg-slate-900 text-white text-[10px] font-black rounded-2xl hover:bg-black transition-all flex items-center gap-2 uppercase tracking-widest shadow-lg shadow-slate-900/10">
                                        <Printer className="w-4 h-4" />
                                        Print Rx
                                     </button>
                                  </div>
                               ))
                            )}
                          </div>
                       </div>
                    </div>
                 )}
              </div>
           </div>
         </div>
      )}
    </div>
  );
};

const DataPoint = ({ label, value }: { label: string, value: string }) => (
  <div className="space-y-1">
    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">{label}</label>
    <p className="font-black text-slate-900 text-lg leading-none">{value}</p>
  </div>
);

export default PatientsView;
